/**
 * Gateway Session - Manages a single client session
 * AgentOS: Session manages chat state and generates all UI via A2UI
 */
export type SendFn = (msg: unknown) => void;

export class GatewaySession {
  agent: PHAAgent | null = null;
  systemAgent: SystemAgent | null = null;
  private config: GatewayConfig;
  sessionId: string;
  saSessionId: string; // Separate session ID for System Agent persistence
  // System Agent sessions are global (not per-user) — use a fixed UUID for storage
  static readonly SA_GLOBAL_UUID = 'system';
  dataSource: HealthDataSource;

  // User identification (from cookie)
  public userUuid: string | null = null;

  // Active push function — bound to the SSE connection on connect.
  // Async tasks (benchmark, agent streaming) use this to push updates.
  private _activeSend: SendFn | null = null;

  // Chat state (Parts model — AG-UI aligned)
  chatMessages: PartsChatMessage[] = [];
  isStreaming = false;
  streamingContent = '';
  currentAssistantMsgId: string | null = null;
  currentRunId: string | null = null;
  lastStreamedText = '';
  currentView = 'chat';
  // AG-UI chat streaming flag: when true, sendChatUpdate is skipped (AG-UI client manages chat state)
  public _sseMode = false;
  private _chatLock = false;

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private extraToolsCache: AgentTool<any>[] | null = null;

  // Legacy-chat independent state
  legacyChatMessages: PartsChatMessage[] = [];
  legacyChatStreaming = false;
  legacyChatStreamingContent = '';
  legacyChatCurrentAssistantMsgId: string | null = null;
  legacyChatCurrentRunId: string | null = null;
  legacyChatLastStreamedText = '';
  legacyChatSessionId: string = crypto.randomUUID();
  legacyChatAgent: PHAAgent | null = null;
  // Tracks which chat channel is active during handleUserMessage / handleAgentEvent
  private _chatChannel: 'main' | 'legacy' = 'main';

  // Settings state
  selectedPrompt: string | null = null;
  selectedSkill: string | null = null;
  selectedSkillFile: string = 'SKILL.md';
  editingPrompt = false;
  editingSkill = false;
  editBuffer: string | null = null;
  // Track which agent collapsible to expand after tag operations
  _settingsExpandedAgent: string | undefined;

  // Scope state for Prompts and Skills pages (PHA ↔ System Agent)
  promptsScope: 'pha' | 'system' = 'pha';
  selectedPromptSource: 'system' | 'user' = 'system';
  skillsCategory: string = 'health-coaching';
  toolsCategory: string = 'all';

  // Memory consolidation counter (daily log → MEMORY.md every N exchanges)
  private exchangeCount = 0;

  // Custom dashboards (persisted per-user)
  customDashboards = new Map<string, DashboardDefinition>();
  activeDashboardTab: string | null = null;

  /** Build a page with sidebar */
  buildPage(view: string, mainPage: A2UIMessage[]): A2UIMessage[] {
    return generatePage(view, mainPage, this.isWhitelisted());
  }

  // Memory system-agent sub-state
  saSelectedMemoryFile: string | null = null;
  saEditingMemory = false;
  evolutionTab: 'overview' | 'traces' | 'evaluations' | 'benchmark' | 'runs' | 'suggestions' | 'config' | 'versions' =
    'overview';
  tracesPage = 0;
  private runningBenchmarks = new Map<string, { modelId: string; presetName?: string; startedAt: number }>();

  private get benchmarkRunning(): boolean {
    return this.runningBenchmarks.size > 0;
  }

  // Dashboard state
  dashboardTab: 'overview' | 'vitals' | 'activity' | 'sleep' | 'body' | 'heart' | 'trends' = 'overview';
  dashboardLoader: ProgressiveDashboardLoader | null = null;
  trendsMetric: string = 'steps';
  trendsRange: string = '1m';

  // Integrations page state
  integrationsTab: 'overview' | 'issues' | 'prs' | 'branches' = 'overview';
  integrationsCache: {
    repo?: unknown;
    issues?: unknown[];
    prs?: unknown[];
    branchInfo?: unknown;
    ghAvailable: boolean;
    timestamp: number;
  } | null = null;

  // Memory page state
  memoryTab: 'profile' | 'summary' | 'logs' | 'search' | 'system-agent' = 'profile';
  memorySearchQuery: string | undefined;
  memorySearchResults: MemorySearchResult[] | undefined;
  selectedLogDate: string | null = null;

  // Plans page state
  plansTab: PlansPageTab = 'active';

  // Logs page state
  logsTab: 'system' | 'llm' = 'system';
  logsLevelFilter: string | undefined;
  logsSubsystemFilter: string | undefined;
  private logsUnsubscribe: (() => void) | null = null;
  private llmLogsUnsubscribe: (() => void) | null = null;
  llmProviderFilter: string | undefined;
  llmModelFilter: string | undefined;
  llmPage: number = 0;

  llmSelectedId: number | undefined;

  // Evolution version state
  activeVersionBranch: string | null = null;

  // Evolution Lab state (5-Tab Dashboard)
  evolutionActiveTab: 'overview' | 'benchmark' | 'versions' | 'data' | 'incidents' = 'overview';
  evolutionDataSubTab: 'traces' | 'evaluations' | 'suggestions' = 'traces';
  evolutionSelectedVersion: string | null = null;
  incidentsFilter: { status?: string; type?: string } = {};
  selectedIncidentId: string | null = null;
  systemAgentChatMessages: PartsChatMessage[] = [];
  systemAgentStreaming = false;
  systemAgentStreamingContent = '';
  saCurrentAssistantMsgId: string | null = null;
  saLastStreamedText = '';
  evolutionInspectedBranch: string | null = null;
  evolutionLabDiffContent: {
    before: string;
    after: string;
    path: string;
    unifiedDiff?: string;
  } | null = null;

  // Workbench state
  workbenchState: import('./workbench-init.js').WorkbenchState | null = null;

  // Arena comparison state
  benchmarkSelectedRunIds: Set<string> = new Set();
  benchmarkRadarMode: 'categories' | 'criteria' = 'categories';

  // Modal state
  modalRadarMode: 'categories' | 'criteria' = 'categories';
  lastViewedBenchmarkRunId: string | null = null;

  constructor(config: GatewayConfig = {}, userUuid?: string, dataSourceOverride?: HealthDataSource) {
    this.config = config;
    this.sessionId = crypto.randomUUID();
    this.saSessionId = crypto.randomUUID();
    this.userUuid = userUuid || null;

    // Use provided data source, or create one based on userUuid
    if (dataSourceOverride) {
      this.dataSource = dataSourceOverride;
    } else if (userUuid) {
      this.dataSource = createDataSourceForUser(userUuid);
      // Always ensure user dir exists so session persistence and memory writes don't ENOENT
      ensureUserDir(userUuid);
    } else {
      this.dataSource = getDataSource();
    }

    // Ensure system agent files exist
    ensureSystemAgentFiles();

    // Load persisted chat history from JSONL
    this.loadPersistedMessages();

    // Load persisted dashboards
    this.loadDashboards();
  }

  // ── Dashboard persistence ──

  private getDashboardsPath(): string | null {
    if (!this.userUuid) {
      return null;
    }
    return join(getUserDir(this.userUuid), 'dashboards.json');
  }

  private loadDashboards(): void {
    const path = this.getDashboardsPath();
    if (!path || !existsSync(path)) {
      return;
    }
    try {
      const data = JSON.parse(readFileSync(path, 'utf-8')) as DashboardDefinition[];
      for (const d of data) {
        this.customDashboards.set(d.id, d);
      }
    } catch {
      // Ignore corrupt file
    }
  }

  private saveDashboards(): void {
    const path = this.getDashboardsPath();
    if (!path) {
      return;
    }
    try {
      writeFileSync(path, JSON.stringify([...this.customDashboards.values()], null, 2), 'utf-8');
    } catch {
      // Ignore write errors
    }
  }

  // Maximum session age before starting a new one (24 hours)
  private static readonly MAX_SESSION_AGE_MS = 24 * 60 * 60 * 1000;

  /**
   * Persist a single message to the JSONL session file.
   * Two channels: "chat" → {sessionId}.jsonl, "system-agent" → sa-{sessionId}.jsonl
   */
  persistMessage(channel: 'chat' | 'legacy-chat' | 'system-agent', entry: SessionEntry): void {
    const sidMap: Record<string, string> = {
      chat: this.sessionId,
      'legacy-chat': `legacy-${this.legacyChatSessionId}`,
      'system-agent': `sa-${this.saSessionId}`,
    };
    const sid = sidMap[channel];
    const uuid = channel === 'system-agent' ? GatewaySession.SA_GLOBAL_UUID : this.userUuid;
    if (!uuid) {
      return;
    }
    try {
      // Resolve session directory from agent profile
      const profileMap: Record<string, string> = {
        chat: 'pha',
        'legacy-chat': 'pha4old',
        'system-agent': 'sa',
      };
      const profileId = profileMap[channel];
      const profile = getAgentProfile(profileId);
      const uidForPath = channel === 'system-agent' ? 'system' : uuid;
      const sessionDir = profile.sessionPath ? resolveSessionPath(profile.sessionPath, uidForPath) : undefined;
      appendToSession(uuid, sid, [entry], sessionDir);
    } catch (err) {
      logSession.warn('Failed to persist message', { error: err });
    }
  }

  /**
   * Load persisted messages from the most recent session.
   * Reuses the session ID if the last message is within 24 hours.
   */
  /**
   * Try to restore a single chat channel from the latest JSONL session file.
   * Returns { sessionId, messages } if a recent session was found, or null.
   */
  private loadSessionChannel(
    uuid: string,
    profileId: string,
    opts?: { prefix?: string; stripPrefix?: string }
  ): { sessionId: string; messages: PartsChatMessage[] } | null {
    const profile = getAgentProfile(profileId);
    const sessionDir = profile.sessionPath ? resolveSessionPath(profile.sessionPath, uuid) : undefined;
    const session = loadLatestSession(uuid, { prefix: opts?.prefix, sessionDir });
    if (!session || session.entries.length === 0) {
      return null;
    }

    const lastTs = session.entries[session.entries.length - 1].timestamp;
    if (Date.now() - lastTs >= GatewaySession.MAX_SESSION_AGE_MS) {
      return null;
    }

    const sid = opts?.stripPrefix
      ? session.sessionId.replace(new RegExp(`^${opts.stripPrefix}`), '')
      : session.sessionId;

    const messages = session.entries
      .filter((e) => e.role === 'user' || e.role === 'assistant')
      .map((e) => ({
        id: crypto.randomUUID(),
        role: e.role as 'user' | 'assistant',
        parts: [{ type: 'text' as const, content: e.content }],
      }));

    return { sessionId: sid, messages };
  }

  private loadPersistedMessages(): void {
    try {
      // Load main chat (per-user)
      if (this.userUuid) {
        const chat = this.loadSessionChannel(this.userUuid, 'pha');
        if (chat) {
          this.sessionId = chat.sessionId;
          this.chatMessages = chat.messages;
        }
      }

      // Load legacy-chat (per-user)
      if (this.userUuid) {
        const legacy = this.loadSessionChannel(this.userUuid, 'pha4old', {
          stripPrefix: 'legacy-',
        });
        if (legacy) {
          this.legacyChatSessionId = legacy.sessionId;
          this.legacyChatMessages = legacy.messages;
        }
      }

      // Load system agent chat
      const sa = this.loadSessionChannel(GatewaySession.SA_GLOBAL_UUID, 'sa', {
        prefix: 'sa-',
        stripPrefix: 'sa-',
      });
      if (sa) {
        this.saSessionId = sa.sessionId;
        this.systemAgentChatMessages = sa.messages;
      }
    } catch (err) {
      logSession.warn('Failed to load persisted messages', { error: err });
    }
  }

  /**
   * Bind the active push function (SSE connection).
   * Called when an SSE connection is established so async tasks
   * (benchmarks, agent streaming) can push to the latest connection.
   */
  setSend(fn: (msg: unknown) => void): void {
    this._activeSend = fn;
  }

  /**
   * Clear the active send function (SSE disconnected).
   */
  clearSend(): void {
    this._activeSend = null;
  }

  /**
   * Get the best available send function.
   * Prefers the live SSE connection (_activeSend) over a stale closure.
   */
  private getSend(fallback: (msg: unknown) => void): (msg: unknown) => void {
    return this._activeSend || fallback;
  }

  /**
   * Check if the current user is authenticated with Huawei
   */
  isUserAuthenticated(): boolean {
    if (!this.userUuid) {
      return false;
    }
    const config = loadConfig();
    if (config.dataSources.type !== 'huawei') return true; // Mock data doesn't need auth
    return huaweiAuth.isUserAuthenticated(this.userUuid);
  }

  /** Check if the current user is in the feature whitelist */
  isWhitelisted(): boolean {
    return isWhitelistedUser(this.userUuid);
  }

  /** Convert PartsChatMessage[] to session messages for agent context recovery */
  private toSessionMessages(msgs: PartsChatMessage[]): Array<{ role: string; content: string }> {
    return msgs.map((m) => ({
      role: m.role,
      content:
        m.parts
          .filter((p) => p.type === 'text')
          .map((p) => (p as { type: 'text'; content: string }).content)
          .join('') || '',
    }));
  }

  /** Common config fields shared between main and legacy agents (model resolved per-agent) */
  private baseAgentConfig(): { userUuid: string | undefined; dataSource: HealthDataSource } {
    return {
      userUuid: this.userUuid || undefined,
      dataSource: this.dataSource,
    };
  }

  /** Ensure extra tools (plugin + remote MCP) are loaded and cached */
  private async ensureExtraTools(): Promise<
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    AgentTool<any>[]
  > {
    if (!this.extraToolsCache) {
      const pluginReg = getGlobalPluginRegistry();
      const pluginTools = pluginReg?.tools.map((r) => r.tool) || [];
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let remoteMcpTools: AgentTool<any>[] = [];
      try {
        remoteMcpTools = await getRemoteMCPTools();
      } catch (err) {
        log.error('Failed to load remote MCP tools', { error: err });
      }
      this.extraToolsCache = [...pluginTools, ...remoteMcpTools];
    }
    return this.extraToolsCache;
  }

  private getLLMConfig(): LLMSummarizationConfig {
    const model = resolveAgentProfileModel('pha');
    return {
      provider: model.provider,
      modelId: model.modelId,
      apiKey: model.apiKey,
      baseUrl: model.baseUrl,
      api: model.provider === 'anthropic' ? 'anthropic-messages' : 'openai-completions',
    };
  }

  private async getAgent(): Promise<PHAAgent> {
    if (!this.agent) {
      const extraTools = await this.ensureExtraTools();
      const model = resolveAgentProfileModel('pha');

      this.agent = await createPHAAgent({
        ...this.baseAgentConfig(),
        apiKey: model.apiKey,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        provider: model.provider as any,
        modelId: model.modelId,
        baseUrl: model.baseUrl,
        profile: getAgentProfile('pha'),
        sessionId: this.sessionId,
        sessionMessages: this.toSessionMessages(this.chatMessages),
        extraTools,
      });

      // Configure evolution tools: create fresh agents per call for concurrency safety
      // (shared agent + concurrent reset = race condition → empty responses)
      const sessionConfig = this.config;
      setEvolutionRunnerConfig({
        agentCall: async (query: string, testCase) => {
          const { seedTestUser, createBenchmarkDataSource, getTestUserUuid } =
            await import('../evolution/test-user-seeder.js');
          const fixture = (await import('../evolution/test-user-seeder.js')).loadTestUserFixture(testCase.userUuid);
          seedTestUser(fixture);
          const dataSource = createBenchmarkDataSource(testCase.userUuid, testCase.healthOverrides);
          const testAgent = await createPHAAgent({
            apiKey: sessionConfig.apiKey,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            provider: sessionConfig.provider as any,
            modelId: sessionConfig.modelId,
            baseUrl: sessionConfig.baseUrl,
            userUuid: getTestUserUuid(testCase.userUuid),
            dataSource,
            sessionMessages: testCase.sessionMessages,
          });
          return withActivityTimeout(testAgent, () => testAgent.chatAndWaitWithTools(query));
        },
        llmCall: async (prompt: string) => {
          const { MockDataSource: JudgeMockDS } = await import('../data-sources/mock.js');
          const judgeAgent = await createPHAAgent({
            apiKey: sessionConfig.apiKey,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            provider: sessionConfig.provider as any,
            modelId: sessionConfig.modelId,
            baseUrl: sessionConfig.baseUrl,
            dataSource: new JudgeMockDS(),
          });
          return withActivityTimeout(judgeAgent, () => judgeAgent.chatAndWait(prompt));
        },
        concurrency: getBenchmarkConcurrency(),
      });
    }
    return this.agent;
  }

  private async getLegacyChatAgent(): Promise<PHAAgent> {
    if (!this.legacyChatAgent) {
      const extraTools = await this.ensureExtraTools();

      // Independent creation: ~150ms (no pre-computation needed)
      const legacyModel = resolveAgentProfileModel('pha4old');
      this.legacyChatAgent = await createPHAAgent({
        ...this.baseAgentConfig(),
        apiKey: legacyModel.apiKey,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        provider: legacyModel.provider as any,
        modelId: legacyModel.modelId,
        baseUrl: legacyModel.baseUrl,
        profile: getAgentProfile('pha4old'),
        sessionId: this.legacyChatSessionId,
        sessionMessages: this.toSessionMessages(this.legacyChatMessages),
        extraTools,
      });
    }
    return this.legacyChatAgent;
  }

  private async getSystemAgent(): Promise<SystemAgent> {
    if (!this.systemAgent) {
      const saModel = resolveAgentProfileModel('sa');
      this.systemAgent = createSystemAgent({
        apiKey: saModel.apiKey,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        provider: saModel.provider as any,
        modelId: saModel.modelId,
        baseUrl: saModel.baseUrl,
        profile: getAgentProfile('sa'),
        sessionMessages: this.systemAgentChatMessages.map((m) => ({
          role: m.role,
          content:
            m.parts
              .filter((p) => p.type === 'text')
              .map((p) => (p as { type: 'text'; content: string }).content)
              .join('') || '',
        })),
      });

      // Configure evolution tools: create fresh agents per call for concurrency safety
      // (NOT the system agent — otherwise responses leak into system agent chat)
      const sessionConfig = this.config;
      setEvolutionRunnerConfig({
        agentCall: async (query: string, testCase) => {
          const { seedTestUser, createBenchmarkDataSource, getTestUserUuid, loadTestUserFixture } =
            await import('../evolution/test-user-seeder.js');
          const fixture = loadTestUserFixture(testCase.userUuid);
          seedTestUser(fixture);
          const dataSource = createBenchmarkDataSource(testCase.userUuid, testCase.healthOverrides);
          const testAgent = await createPHAAgent({
            apiKey: sessionConfig.apiKey,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            provider: sessionConfig.provider as any,
            modelId: sessionConfig.modelId,
            baseUrl: sessionConfig.baseUrl,
            userUuid: getTestUserUuid(testCase.userUuid),
            dataSource,
            sessionMessages: testCase.sessionMessages,
          });
          return withActivityTimeout(testAgent, () => testAgent.chatAndWaitWithTools(query));
        },
        llmCall: async (prompt: string) => {
          const { MockDataSource: JudgeMockDS } = await import('../data-sources/mock.js');
          const judgeAgent = await createPHAAgent({
            apiKey: sessionConfig.apiKey,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            provider: sessionConfig.provider as any,
            modelId: sessionConfig.modelId,
            baseUrl: sessionConfig.baseUrl,
            dataSource: new JudgeMockDS(),
          });
          return withActivityTimeout(judgeAgent, () => judgeAgent.chatAndWait(prompt));
        },
        concurrency: getBenchmarkConcurrency(),
        onProgress: (current, total, _testCase) => {
          // Update the last running run_benchmark tool_use part with progress
          for (let i = this.systemAgentChatMessages.length - 1; i >= 0; i--) {
            const msg = this.systemAgentChatMessages[i];
            if (msg.role !== 'assistant' || !msg.parts) {
              continue;
            }
            for (let j = msg.parts.length - 1; j >= 0; j--) {
              const part = msg.parts[j];
              if (part.type === 'tool_use' && part.toolName === 'run_benchmark' && part.status === 'running') {
                // Store progress info as extra field on the part (extended type)
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                (part as any).progressData = { current, total };
                break;
              }
            }
          }
          const send = this._activeSend;
          if (send) {
            this.sendEvolutionLabUpdateThrottled(send);
          }
        },
      });
    }
    return this.systemAgent;
  }

  /**
   * Switch the agent to read prompts/skills from a specific version branch.
   * Pass null to reset back to the default (main) paths.
   */
  switchAgentVersion(branch: string | null): void {
    if (branch) {
      const worktreePath = getWorktreePath(branch);
      setPromptsDir(join(worktreePath, 'src/prompts/pha'));
      setSkillsDir(join(worktreePath, 'src/skills'));
    } else {
      setPromptsDir('src/prompts/pha');
      setSkillsDir('src/skills');
    }
    this.agent = null; // Force agent rebuild with new paths (skill registry rebuilds automatically)
    this.activeVersionBranch = branch;
  }

  // Per-session action lock for HTTP requests (prevents concurrent mutations)
  private _actionLock = false;
  // AbortController for cancelling in-progress navigation (e.g., dashboard data loading)
  private _navAbort: AbortController | null = null;

  /**
   * Handle incoming message (from HTTP action endpoint or legacy WS)
   */
  async handleMessage(data: WSMessage, send: (msg: unknown) => void): Promise<void> {
    switch (data.type) {
      case 'init':
        await this.handleInit(send);
        break;
      case 'navigate':
        await this.handleNavigate((data as WSNavigateMessage).view, send);
        break;
      case 'user_message':
        await this.handleUserMessage((data as WSUserMessage).content, send);
        break;
      case 'action':
        await this.handleAction((data as WSActionMessage).action, (data as WSActionMessage).payload, send);
        break;
      case 'ping':
        send({ type: 'pong' });
        break;
      default:
        log.warn('Unknown message type', { type: data.type });
    }
  }

  // ========================================================================
  // HTTP+SSE Public API (A2UI over HTTP)
  // ========================================================================

  /**
   * Get the session ID.
   */
  getSessionId(): string {
    return this.sessionId;
  }

  /**
   * Get the full page state for the current view (used by POST /api/a2ui/init).
   * Uses a collector to capture all send() calls and return them.
   */
  async getFullPageState(clientView?: string | null): Promise<unknown[]> {
    const collected: unknown[] = [];
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const collector = (msg: unknown) => collected.push(msg);

    // Restore benchmark running state
    const allProgress = readAllBenchmarkProgress();
    for (const [trackingId, info] of Object.entries(allProgress)) {
      if (info.source === 'ui' && trackingId !== '__cli__') {
        this.runningBenchmarks.set(trackingId, {
          modelId: info.modelId || '',
          presetName: info.presetName,
          startedAt: info.startedAt,
        });
      }
    }

    // Use client-provided view on reconnect (avoids cross-browser sync),
    // fall back to session's currentView for first connection
    const view = clientView || this.currentView;
    await this.handleNavigate(view, collector);
    return collected;
  }

  /**
   * Handle an HTTP action/navigate request.
   * Captures synchronous send() calls and returns them as updates.
   * Async updates (benchmark progress, streaming) go through SSE.
   */
  async handleHTTPRequest(data: {
    type: string;
    action?: string;
    payload?: Record<string, unknown>;
    view?: string;
  }): Promise<{ updates: unknown[] }> {
    const isNavigate = data.type === 'navigate' && data.view;

    // Navigation requests bypass the action lock so users can switch tabs
    // even while a slow page (e.g., dashboard) is loading.
    // Cancel any in-progress navigation first.
    if (isNavigate) {
      if (this._navAbort) {
        this._navAbort.abort();
        this._navAbort = null;
      }
      // Release the action lock if held by previous navigation
      this._actionLock = false;
    } else if (this._actionLock) {
      return { updates: [{ type: 'error', message: 'Action in progress' }] };
    }

    this._actionLock = true;

    const collected: unknown[] = [];
    // Collect messages for the HTTP response only.
    // Do NOT duplicate to SSE — the client processes the HTTP response
    // synchronously, so pushing the same messages through SSE causes
    // double-rendering and visual "flash-back" on page transitions.
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const collector = (msg: unknown) => {
      collected.push(msg);
    };

    try {
      if (isNavigate) {
        this._navAbort = new AbortController();
        await this.handleNavigate(data.view!, collector, this._navAbort.signal);
        this._navAbort = null;
      } else if (data.type === 'action' && data.action) {
        await this.handleAction(data.action, data.payload, collector);
      } else if (data.type === 'user_message' && data.payload?.content) {
        await this.handleUserMessage(data.payload.content as string, collector);
      }
    } finally {
      this._actionLock = false;
    }

    return { updates: collected };
  }

  private async handleInit(send: (msg: unknown) => void, clientView?: string | null): Promise<void> {
    send({
      type: 'connected',
      session_id: this.sessionId,
    });

    // Restore benchmark running state from all progress files
    const allProgress = readAllBenchmarkProgress();
    for (const [trackingId, info] of Object.entries(allProgress)) {
      if (info.source === 'ui' && trackingId !== '__cli__') {
        this.runningBenchmarks.set(trackingId, {
          modelId: info.modelId || '',
          presetName: info.presetName,
          startedAt: info.startedAt,
        });
      }
    }

    // Use client-provided view on reconnect (avoids cross-browser sync),
    // fall back to session's currentView for first connection
    const view = clientView || this.currentView;
    await this.handleNavigate(view, send);
  }

  /** OpenClaw standard: 5 system-level + 3 user-level = 8 files */
  private static readonly OPENCLAW_SYSTEM_FILES = ['SOUL', 'IDENTITY', 'AGENTS', 'TOOLS', 'HEARTBEAT'];
  private static readonly OPENCLAW_USER_FILES = ['USER', 'MEMORY', 'BOOTSTRAP'];

  /**
   * Build the fixed 8-file list for OpenClaw alignment.
   * Files that don't exist yet still appear with exists=false.
   */
  private buildOpenClaw8Files(): Array<{
    name: string;
    filename: string;
    title: string;
    lines: number;
    source: 'system' | 'user';
    exists: boolean;
  }> {
    const systemDir = this.promptsScope === 'system' ? 'src/prompts/system-agent' : 'src/prompts/pha';
    let userDir: string;
    if (this.promptsScope === 'system') {
      userDir = join(getStateDir(), 'users', 'system');
    } else {
      const uuid = this.userUuid || getUserId() || 'anonymous';
      userDir = getUserDir(uuid);
    }

    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const readFileInfo = (filePath: string) => {
      if (!existsSync(filePath)) {
        return { exists: false, title: '—', lines: 0 };
      }
      try {
        const content = readFileSync(filePath, 'utf-8');
        const contentLines = content.split('\n');
        const title = contentLines.find((l) => l.startsWith('# '))?.slice(2) || '';
        return { exists: true, title, lines: contentLines.length };
      } catch {
        return { exists: false, title: '—', lines: 0 };
      }
    };

    const result: Array<{
      name: string;
      filename: string;
      title: string;
      lines: number;
      source: 'system' | 'user';
      exists: boolean;
    }> = [];

    // 5 system-level files
    for (const name of GatewaySession.OPENCLAW_SYSTEM_FILES) {
      const filename = `${name}.md`;
      const info = readFileInfo(join(systemDir, filename));
      result.push({ name, filename, source: 'system', ...info });
    }

    // 3 user-level files
    for (const name of GatewaySession.OPENCLAW_USER_FILES) {
      const filename = `${name}.md`;
      const info = readFileInfo(join(userDir, filename));
      result.push({ name, filename, source: 'user', ...info });
    }

    return result;
  }

  /**
   * Get the full file path for a user-level file.
   */
  /** Open prompt detail modal with content + git history */
  async openPromptModal(send: (msg: unknown) => void): Promise<void> {
    if (!this.selectedPrompt) {
      return;
    }

    let content = '';
    let commits: Array<{
      hash: string;
      shortHash: string;
      message: string;
      date: string;
      author: string;
    }> = [];

    if (this.selectedPromptSource === 'user') {
      const filePath = this.getUserFilePath(this.selectedPrompt);
      if (filePath && existsSync(filePath)) {
        content = this.editBuffer ?? readFileSync(filePath, 'utf-8');
      } else {
        content = this.editBuffer ?? '';
      }
    } else {
      setPromptsDir(this.promptsScope === 'system' ? 'src/prompts/system-agent' : 'src/prompts/pha');
      try {
        const promptResult = await getPromptTool.execute({ name: this.selectedPrompt });
        if (promptResult.success) {
          content = this.editBuffer ?? (promptResult.content as string);
        }
        const historyResult = await getPromptHistoryTool.execute({
          name: this.selectedPrompt,
          limit: 10,
        });
        if (historyResult.success && historyResult.commits) {
          commits = historyResult.commits as typeof commits;
        }
      } finally {
        setPromptsDir('src/prompts/pha');
      }
    }

    const modal = generatePromptDetailModal({
      name: this.selectedPrompt,
      source: this.selectedPromptSource,
      content,
      editing: this.editingPrompt,
      commits,
    });
    sendAll(send, modal);
  }

  getUserFilePath(name: string): string | null {
    const filename = name.endsWith('.md') ? name : `${name}.md`;
    let dir: string;
    if (this.promptsScope === 'system') {
      dir = join(getStateDir(), 'users', 'system');
    } else {
      const uuid = this.userUuid || getUserId() || 'anonymous';
      if (!uuid) {
        return null;
      }
      dir = getUserDir(uuid);
    }
    return join(dir, filename);
  }

  async handleNavigate(view: string, send: (msg: unknown) => void, signal?: AbortSignal): Promise<void> {
    await dispatchNavigation(this, view, send, signal);
  }

  /** Set streaming flags at the start of a chat turn. */
  private setStreamingStart(isLegacy: boolean): void {
    if (isLegacy) {
      this.legacyChatStreaming = true;
      this.legacyChatStreamingContent = '';
      this.legacyChatCurrentAssistantMsgId = null;
      this.legacyChatCurrentRunId = null;
      this.legacyChatLastStreamedText = '';
    } else {
      this.isStreaming = true;
      this.streamingContent = '';
      this.currentAssistantMsgId = null;
      this.currentRunId = null;
      this.lastStreamedText = '';
    }
  }

  /** Clear streaming flags. Returns true if streaming was still active. */
  private clearStreamingState(isLegacy: boolean): boolean {
    const wasStreaming = isLegacy ? this.legacyChatStreaming : this.isStreaming;
    if (isLegacy) {
      this.legacyChatStreaming = false;
      this.legacyChatStreamingContent = '';
      this.legacyChatCurrentAssistantMsgId = null;
      this.legacyChatLastStreamedText = '';
    } else {
      this.isStreaming = false;
      this.streamingContent = '';
      this.currentAssistantMsgId = null;
      this.lastStreamedText = '';
    }
    return wasStreaming;
  }

  /** Run agent chat (with skill hint if applicable) and return called tool names. */
  private async runAgentChat(agent: PHAAgent, content: string, send: (msg: unknown) => void): Promise<Set<string>> {
    const calledTools = new Set<string>();
    const unsubscribe = agent.subscribe((event) => {
      if (event.type === 'tool_execution_end' && !event.isError) {
        calledTools.add(event.toolName);
      }
      this.handleAgentEvent(event, send);
    });
    try {
      const skillHint = agent.getSkillHint();
      if (skillHint) {
        await agent.chatWithSkill(content, skillHint);
      } else {
        await agent.chat(content);
      }
      await agent.getAgent().waitForIdle();
    } finally {
      unsubscribe();
    }
    return calledTools;
  }

  /** Index a user/assistant exchange for memory search and auto-save daily log. */
  private indexExchangeForMemory(
    content: string,
    messages: PartsChatMessage[],
    sessionId: string,
    calledTools: Set<string>
  ): void {
    if (!this.userUuid) {
      return;
    }
    try {
      const mm = getMemoryManager();
      const lastAssistant = messages.filter((m) => m.role === 'assistant').pop();
      if (!lastAssistant) {
        return;
      }
      const assistantText = lastAssistant.parts
        .filter((p): p is { type: 'text'; content: string } => p.type === 'text')
        .map((p) => p.content)
        .join('');
      mm.appendSessionTranscript(this.userUuid, sessionId, `User: ${content}\nAssistant: ${assistantText}`);
      if (!calledTools.has('daily_log') && assistantText.length > 20) {
        mm.appendDailyLog(
          this.userUuid,
          `- 用户: ${content.slice(0, 100)}\n- 助手: ${assistantText.replace(/\s+/g, ' ').slice(0, 200)}`
        );
      }
      this.exchangeCount++;
      if (this.exchangeCount % 5 === 0 && !calledTools.has('memory_save')) {
        void consolidateMemory(this.userUuid, this.getLLMConfig(), mm).catch(() => {});
      }
    } catch {
      /* best-effort */
    }
  }

  /** Fallback: check agent internal messages for LLM errors not caught by event handler. */
  private checkAgentFallbackError(
    agent: PHAAgent,
    messages: PartsChatMessage[],
    countBefore: number,
    persistChannel: 'chat' | 'legacy-chat'
  ): void {
    if (messages.slice(countBefore).some((m) => m.role === 'assistant')) {
      return;
    }
    const agentMsgs = agent.getMessages();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const last = agentMsgs[agentMsgs.length - 1] as any;
    if (last?.stopReason === 'error' && last?.errorMessage) {
      const errContent = `⚠️ ${last.errorMessage}`;
      messages.push({
        id: crypto.randomUUID(),
        role: 'assistant',
        parts: [{ type: 'text', content: errContent }],
      });
      this.persistMessage(persistChannel, {
        timestamp: Date.now(),
        role: 'assistant',
        content: errContent,
      });
      log.warn('LLM error caught by fallback (not by event handler)', {
        errorMessage: last.errorMessage,
      });
    }
  }

  /** Handle errors thrown during chat (A2UI mode). */
  private handleChatError(
    error: unknown,
    isLegacy: boolean,
    messages: PartsChatMessage[],
    persistChannel: 'chat' | 'legacy-chat',
    sessionId: string,
    send: (msg: unknown) => void
  ): void {
    const stillStreaming = isLegacy ? this.legacyChatStreaming : this.isStreaming;
    if (!stillStreaming) {
      return;
    }
    if (isLegacy) {
      this.legacyChatStreaming = false;
    } else {
      this.isStreaming = false;
    }
    const isAbort = error instanceof Error && (error.name === 'AbortError' || /abort/i.test(error.message));
    if (isAbort) {
      this.sendChatUpdate(send);
      return;
    }
    const errorContent = `Error: ${error instanceof Error ? error.message : String(error)}`;
    messages.push({
      id: crypto.randomUUID(),
      role: 'assistant',
      parts: [{ type: 'text', content: errorContent }],
    });
    this.persistMessage(persistChannel, {
      timestamp: Date.now(),
      role: 'assistant',
      content: errorContent,
    });
    this.sendChatUpdate(send);
    logAgent.error('Agent error', { sessionId, error });
    send({
      type: 'error',
      code: 'agent_error',
      message: error instanceof Error ? error.message : String(error),
    });
  }

  async handleUserMessage(content: string, send: (msg: unknown) => void): Promise<void> {
    const isLegacy = this.currentView === 'legacy-chat';
    this._chatChannel = isLegacy ? 'legacy' : 'main';
    const messages = isLegacy ? this.legacyChatMessages : this.chatMessages;
    const persistChannel = isLegacy ? ('legacy-chat' as const) : ('chat' as const);
    const sessionId = isLegacy ? this.legacyChatSessionId : this.sessionId;

    messages.push({ id: crypto.randomUUID(), role: 'user', parts: [{ type: 'text', content }] });
    this.persistMessage(persistChannel, { timestamp: Date.now(), role: 'user', content });
    const hr = getGlobalHookRunner();
    if (hr) {
      hr.runMessageReceived(
        { from: this.userUuid || 'unknown', content, timestamp: Date.now() },
        { channelId: 'http', conversationId: sessionId }
      ).catch((err) => log.warn('Hook message_received error', { error: err }));
    }
    this.setStreamingStart(isLegacy);
    this.sendChatUpdate(send);
    const countBefore = messages.length;

    try {
      const agent = isLegacy ? await this.getLegacyChatAgent() : await this.getAgent();
      const calledTools = await this.runAgentChat(agent, content, send);
      this.checkAgentFallbackError(agent, messages, countBefore, persistChannel);
      if (this.clearStreamingState(isLegacy)) {
        this.sendChatUpdate(send);
      }
      this.indexExchangeForMemory(content, messages, sessionId, calledTools);
    } catch (error) {
      this.handleChatError(error, isLegacy, messages, persistChannel, sessionId, send);
    }
  }

  sendChatUpdate(send: (msg: unknown) => void): void {
    const activeSend = this.getSend(send);
    if (this._sseMode) {
      return;
    }
    if (this.currentView === 'chat' || this.currentView === 'legacy-chat') {
      const isLegacy = this.currentView === 'legacy-chat';
      const chatPage = generateChatPage({
        messages: isLegacy ? this.legacyChatMessages : this.chatMessages,
        streaming: isLegacy ? this.legacyChatStreaming : this.isStreaming,
        streamingContent: isLegacy ? this.legacyChatStreamingContent : this.streamingContent,
        ...(isLegacy ? { thinkingMode: true } : {}),
      });
      sendAll(activeSend, chatPage);
    }
  }

  /**
   * Handle an SSE chat request. Returns a ReadableStream of AG-UI SSE events.
   */
  async handleChatSSE(
    content: string,
    writer: WritableStreamDefaultWriter<Uint8Array>,
    encoder: TextEncoder
  ): Promise<void> {
    if (this._chatLock) {
      sseWriteAndClose(writer, encoder, JSON.stringify({ type: 'error', message: 'Chat is busy' }));
      return;
    }
    this._chatLock = true;
    this._sseMode = true;
    const stream = createSafeSSEStream(writer, encoder);
    const sseSend = createAGUISender(stream.write);
    const isLegacy = this.currentView === 'legacy-chat';
    this._chatChannel = isLegacy ? 'legacy' : 'main';
    const messages = isLegacy ? this.legacyChatMessages : this.chatMessages;
    const persistChannel = isLegacy ? ('legacy-chat' as const) : ('chat' as const);
    const sessionId = isLegacy ? this.legacyChatSessionId : this.sessionId;

    try {
      messages.push({ id: crypto.randomUUID(), role: 'user', parts: [{ type: 'text', content }] });
      this.persistMessage(persistChannel, { timestamp: Date.now(), role: 'user', content });
      this.setStreamingStart(isLegacy);
      const agent = isLegacy ? await this.getLegacyChatAgent() : await this.getAgent();
      const calledTools = await this.runAgentChat(agent, content, sseSend);
      this.clearStreamingState(isLegacy);
      this.indexExchangeForMemory(content, messages, sessionId, calledTools);
    } catch (error) {
      const isAbort = error instanceof Error && (error.name === 'AbortError' || /abort/i.test(error.message));
      if (!isAbort) {
        stream.write(
          `data: ${JSON.stringify({ type: 'Custom', name: 'Error', data: { message: error instanceof Error ? error.message : String(error) } })}\n\n`
        );
      }
      this.clearStreamingState(isLegacy);
    } finally {
      this._sseMode = false;
      this._chatLock = false;
      stream.close();
    }
  }

  /**
   * Get or create the current system-agent assistant message.
   */
  private saGetOrCreateAssistantMsg(): PartsChatMessage {
    if (this.saCurrentAssistantMsgId) {
      const existing = this.systemAgentChatMessages.find((m) => m.id === this.saCurrentAssistantMsgId);
      if (existing) {
        return existing;
      }
    }
    const msg: PartsChatMessage = {
      id: crypto.randomUUID(),
      role: 'assistant',
      parts: [],
    };
    this.systemAgentChatMessages.push(msg);
    this.saCurrentAssistantMsgId = msg.id;
    return msg;
  }

  /**
   * Fire-and-forget wrapper: starts SA processing in background,
   * sends initial streaming UI update immediately, and returns.
   * This prevents the action lock from being held during LLM inference.
   */
  fireSystemAgentMessage(content: string, send: (msg: unknown) => void): void {
    // Use SSE send if available (preferred over HTTP collector)
    const sseSend = this.getSend(send);
    this.handleSystemAgentMessage(content, sseSend).catch((err: unknown) => {
      logEvolution.error('SA message failed', { error: err });
    });
    // Send initial UI update to show streaming state
    this.sendEvolutionLabUpdate(send);
  }

  private async handleSystemAgentMessage(content: string, send: (msg: unknown) => void): Promise<void> {
    this.systemAgentChatMessages.push({
      id: crypto.randomUUID(),
      role: 'user',
      parts: [{ type: 'text', content }],
    });
    this.persistMessage('system-agent', { timestamp: Date.now(), role: 'user', content });
    this.systemAgentStreaming = true;
    this.systemAgentStreamingContent = '';
    this.saCurrentAssistantMsgId = null;
    this.saLastStreamedText = '';

    // Add empty assistant placeholder so loading dots show immediately
    const placeholder: PartsChatMessage = {
      id: crypto.randomUUID(),
      role: 'assistant',
      parts: [],
    };
    this.systemAgentChatMessages.push(placeholder);
    this.saCurrentAssistantMsgId = placeholder.id;

    this.sendEvolutionLabUpdate(send);

    try {
      const agent = await this.getSystemAgent();

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const unsubscribe = agent.subscribe((event: any) => {
        this._handleSAEvent(event, send);
      });

      try {
        // Force-inject evolution-driver skill (Task #8)
        await agent.chatWithSkill(content, 'evolution-driver');
        await agent.getAgent().waitForIdle();
      } finally {
        unsubscribe();
      }
    } catch (error) {
      // If already handled by sa_stop_generation (streaming flag cleared), skip error handling
      if (!this.systemAgentStreaming) {
        return;
      }
      this.systemAgentStreaming = false;

      // Abort errors are expected when user clicks stop
      const isAbort = error instanceof Error && (error.name === 'AbortError' || /abort/i.test(error.message));
      if (isAbort) {
        this.sendEvolutionLabUpdate(send);
        return;
      }

      const errorContent = `Error: ${error instanceof Error ? error.message : String(error)}`;
      this.systemAgentChatMessages.push({
        id: crypto.randomUUID(),
        role: 'assistant',
        parts: [{ type: 'text', content: errorContent }],
      });
      this.persistMessage('system-agent', {
        timestamp: Date.now(),
        role: 'assistant',
        content: errorContent,
      });
      this.sendEvolutionLabUpdate(send);
    }
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private _handleSAEvent(event: any, send: (msg: unknown) => void): void {
    const SA_EVENT_HANDLERS: Record<string, (ev: any, s: (msg: unknown) => void) => void> = {
      message_start: (ev, s) => this._handleSAMessageStart(ev, s),
      message_update: (ev, s) => this._handleSAMessageUpdate(ev, s),
      message_end: (ev, s) => this._handleSAMessageEnd(ev, s, extractSAText),
      tool_execution_start: (ev, s) => this._handleSAToolStart(ev, s),
      tool_execution_end: (ev, s) => this._handleSAToolEnd(ev, s),
      agent_end: (_ev, s) => {
        this.systemAgentStreaming = false;
        this.saCurrentAssistantMsgId = null;
        this.saLastStreamedText = '';
        this.sendEvolutionLabUpdate(s);
      },
    };

    const handler = SA_EVENT_HANDLERS[event.type];
    if (handler) {
      handler(event, send);
    }
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private _handleSAMessageStart(event: any, send: (msg: unknown) => void): void {
    if (event.message?.role !== 'assistant') {
      return;
    }
    const text = extractSAText(event.message.content || []);
    const assistantMsg = this.saGetOrCreateAssistantMsg();
    if (text) {
      assistantMsg.parts.push({ type: 'text', content: text });
    }
    this.systemAgentStreamingContent = text;
    this.saLastStreamedText = text;
    this.sendEvolutionLabUpdate(send);
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private _handleSAMessageUpdate(event: any, send: (msg: unknown) => void): void {
    if (event.message?.role !== 'assistant') {
      return;
    }
    const text = extractSAText(event.message.content || []);
    this.systemAgentStreamingContent = text;
    const assistantMsg = this.saGetOrCreateAssistantMsg();
    const lastPart = assistantMsg.parts[assistantMsg.parts.length - 1];
    if (lastPart && lastPart.type === 'text') {
      lastPart.content = text;
    } else if (text) {
      assistantMsg.parts.push({ type: 'text', content: text });
    }
    this.saLastStreamedText = text;
    this.sendEvolutionLabUpdateThrottled(send);
    const activeSend = this.getSend(send);
    activeSend({ type: 'agent_text', content: text, is_final: false });
  }

  private _handleSAMessageEnd(event: any, send: (msg: unknown) => void, extractText: (c: unknown[]) => string): void {
    if (event.message?.role !== 'assistant') {
      return;
    }
    const text = extractText(event.message.content || []);
    if (text.trim()) {
      const assistantMsg = this.saGetOrCreateAssistantMsg();
      const lastTextIdx = findLastTextIdx(assistantMsg.parts);
      if (lastTextIdx >= 0) {
        (assistantMsg.parts[lastTextIdx] as { type: 'text'; content: string }).content = text;
      } else {
        assistantMsg.parts.push({ type: 'text', content: text });
      }
      this.persistMessage('system-agent', {
        timestamp: Date.now(),
        role: 'assistant',
        content: text,
      });
    }
    this.systemAgentStreamingContent = '';
    this.saLastStreamedText = '';
    this.sendEvolutionLabUpdate(send);
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private _handleSAToolStart(event: any, send: (msg: unknown) => void): void {
    const toolName = event.toolName as string;
    const toolCallId = crypto.randomUUID();
    const assistantMsg = this.saGetOrCreateAssistantMsg();
    const lastPart = assistantMsg.parts[assistantMsg.parts.length - 1];
    if (lastPart && lastPart.type === 'text' && !lastPart.content.trim()) {
      assistantMsg.parts.pop();
    }
    assistantMsg.parts.push({ type: 'tool_use', toolCallId, toolName, status: 'running' });
    this.sendEvolutionLabUpdate(send);
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private _handleSAToolEnd(event: any, send: (msg: unknown) => void): void {
    const toolName = event.toolName as string;
    const isError = event.isError;
    const assistantMsg = this.saCurrentAssistantMsgId
      ? this.systemAgentChatMessages.find((m) => m.id === this.saCurrentAssistantMsgId)
      : null;
    if (assistantMsg) {
      let matchedToolCallId: string | null = null;
      for (let i = assistantMsg.parts.length - 1; i >= 0; i--) {
        const part = assistantMsg.parts[i];
        if (part.type === 'tool_use' && part.toolName === toolName && part.status === 'running') {
          part.status = isError ? 'error' : 'completed';
          matchedToolCallId = part.toolCallId;
          break;
        }
      }
      if (!isError && matchedToolCallId) {
        try {
          const cards = generateToolCards(toolName, event.result);
          if (cards) {
            assistantMsg.parts.push({ type: 'tool_result', toolCallId: matchedToolCallId, cards });
          }
        } catch (err) {
          logAgent.error('System Agent card generation error', { error: err });
        }
      }
      assistantMsg.parts.push({ type: 'text', content: '' });
      this.saLastStreamedText = '';
    }
    this.sendEvolutionLabUpdate(send);
  }

  private async handleAction(
    action: string,
    payload: Record<string, unknown> | undefined,
    send: (msg: unknown) => void
  ): Promise<void> {
    await dispatchAction(this, action, payload, send);
  }

  /**
   * Load integrations data asynchronously and re-send the page.
   * Caches results so tab switches are instant.
   */
  async loadIntegrationsAsync(send: (msg: unknown) => void): Promise<void> {
    let ghAvailable = true;

    try {
      const { getRepoInfo, listIssues, listPRs, getBranchInfo } = await import('../integrations/github.js');

      // Load all data in parallel for caching
      const [repo, issues, prs, branchInfo] = await Promise.all([
        getRepoInfo().catch(() => null),
        listIssues(20).catch(() => []),
        listPRs(20).catch(() => []),
        getBranchInfo().catch(() => undefined),
      ]);

      if (!repo) {
        ghAvailable = false;
      }

      // Cache everything
      this.integrationsCache = {
        repo,
        issues,
        prs,
        branchInfo,
        ghAvailable,
        timestamp: Date.now(),
      };
    } catch {
      ghAvailable = false;
      this.integrationsCache = { ghAvailable: false, timestamp: Date.now() };
    }

    sendAll(
      send,
      this.buildPage(
        'settings/integrations',
        generateIntegrationsPage({
          activeTab: this.integrationsTab,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          repo: this.integrationsCache?.repo as any,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          issues: this.integrationsCache?.issues as any,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          prs: this.integrationsCache?.prs as any,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          branchInfo: this.integrationsCache?.branchInfo as any,
          ghAvailable,
        })
      )
    );
  }

  /**
   * Load tab-specific integrations data that wasn't in the initial cache
   */
  async loadIntegrationsTabData(send: (msg: unknown) => void): Promise<void> {
    if (!this.integrationsCache) {
      return;
    }

    const { listIssues, listPRs, getBranchInfo } = await import('../integrations/github.js');

    let updated = false;

    if (this.integrationsTab === 'issues' && !this.integrationsCache.issues?.length) {
      this.integrationsCache.issues = await listIssues(30).catch(() => []);
      updated = true;
    } else if (this.integrationsTab === 'prs' && !this.integrationsCache.prs?.length) {
      this.integrationsCache.prs = await listPRs(20).catch(() => []);
      updated = true;
    } else if (this.integrationsTab === 'branches' && !this.integrationsCache.branchInfo) {
      this.integrationsCache.branchInfo = await getBranchInfo().catch(() => undefined);
      updated = true;
    }

    if (updated) {
      sendAll(
        send,
        this.buildPage(
          'settings/integrations',
          generateIntegrationsPage({
            activeTab: this.integrationsTab,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            repo: this.integrationsCache.repo as any,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            issues: this.integrationsCache.issues as any,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            prs: this.integrationsCache.prs as any,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            branchInfo: this.integrationsCache.branchInfo as any,
            ghAvailable: this.integrationsCache.ghAvailable,
          })
        )
      );
    }
  }

  /**
   * Build data for the Evolution Lab 5-Tab Dashboard.
   */
  private buildEvolutionLabData(): EvolutionLabData {
    const activeTab = this.evolutionActiveTab;
    const common = this._loadBenchmarkRunsCommon();

    // Auto-select most recent 3 completed runs if user hasn't manually selected any
    if (this.benchmarkSelectedRunIds.size === 0 && common.benchmarkRuns) {
      const completedRuns = common.benchmarkRuns
        .filter((r) => r.status === 'completed' && r.overall_score > 0)
        .slice(0, 3);
      for (const r of completedRuns) {
        this.benchmarkSelectedRunIds.add(r.id);
      }
    }

    const isOverviewOrBenchmark = activeTab === 'overview' || activeTab === 'benchmark';
    const hasSelectedRuns = this.benchmarkSelectedRunIds.size > 0;

    // Load tab-specific data
    const tabSpecific = this._loadEvolutionTabSpecific(activeTab, common.benchmarkRuns);

    return {
      activeTab,
      ...common,
      activeVersionBranch: this.activeVersionBranch,
      selectedRunIds: hasSelectedRuns ? Array.from(this.benchmarkSelectedRunIds) : undefined,
      radarMode: this.benchmarkRadarMode,
      comparisonRuns: isOverviewOrBenchmark && hasSelectedRuns ? this._loadComparisonRuns() : undefined,
      externalProgressMap: isOverviewOrBenchmark ? loadExternalProgressMap() : undefined,
      testCases: activeTab === 'benchmark' ? loadBenchmarkTestCases() : undefined,
      selectedVersion: this.evolutionSelectedVersion || undefined,
      diffContent: this.evolutionLabDiffContent || undefined,
      dataSubTab: this.evolutionDataSubTab,
      tracesPage: this.tracesPage,
      ...tabSpecific,
      incidentsFilter: this.incidentsFilter,
    };
  }

  /** Load tab-specific data fragments for the Evolution Lab. */
  private _loadEvolutionTabSpecific(
    activeTab: string,
    benchmarkRuns: EvolutionLabData['benchmarkRuns']
  ): Partial<EvolutionLabData> {
    switch (activeTab) {
      case 'overview':
        return this._loadOverviewTabData();
      case 'versions':
        return this._loadVersionsTabData(benchmarkRuns);
      case 'data':
        return this._loadDataTabData();
      case 'incidents':
        return this._loadIncidentsTabData();
      default:
        return {};
    }
  }

  /** Load incidents tab data. */
  private _loadIncidentsTabData(): Pick<EvolutionLabData, 'incidents' | 'incidentStats'> {
    try {
      const filter = this.incidentsFilter;
      const rows = listIncidents({
        status: filter.status as IncidentStatus | undefined,
        type: filter.type as IncidentType | undefined,
        limit: 100,
      });
      return {
        incidents: rows.map((r: IncidentRow) => ({
          id: r.id,
          timestamp: r.timestamp,
          source: r.source,
          reporter: r.reporter,
          rawText: r.raw_text,
          traceId: r.trace_id,
          type: r.type,
          status: r.status,
          priority: r.priority,
          classificationConfidence: r.classification_confidence,
          classificationReason: r.classification_reason,
          githubIssueUrl: r.github_issue_url,
          githubIssueNumber: r.github_issue_number,
          notes: r.notes,
        })),
        incidentStats: getIncidentStats(),
      };
    } catch {
      return {};
    }
  }

  /** Load benchmark runs (common across tabs). */
  private _loadBenchmarkRunsCommon(): Pick<
    EvolutionLabData,
    'benchmarkRuns' | 'latestCategoryScores' | 'latestRunCategoryScores'
  > {
    try {
      const runs = listBenchmarkRuns({ limit: 20 });
      const cfg = getBenchmarkModels();
      const benchmarkRuns = runs.map((r) => mapBenchmarkRun(r, cfg));
      const bestScores = getBestCategoryScores();
      const latestCategoryScores =
        bestScores.length > 0
          ? bestScores.map((s) => ({
              category: s.category,
              score: s.score,
              test_count: s.test_count,
              passed_count: s.passed_count,
            }))
          : undefined;
      let latestRunCategoryScores: EvolutionLabData['latestRunCategoryScores'];
      if (runs.length > 0) {
        try {
          const ls = listCategoryScores(runs[0].id);
          if (ls.length > 0) {
            latestRunCategoryScores = parseAndReAggregateScores(ls);
          }
        } catch {
          /* ok */
        }
      }
      return { benchmarkRuns, latestCategoryScores, latestRunCategoryScores };
    } catch {
      return {};
    }
  }

  /** Load overview-specific data (stats, trend, counts). */
  private _loadOverviewTabData(): Pick<EvolutionLabData, 'stats' | 'scoreTrend' | 'versionCount' | 'testCaseCount'> {
    let stats: EvolutionLabData['stats'];
    let scoreTrend: EvolutionLabData['scoreTrend'];
    let testCaseCount = 0;
    let versionCount = 0;
    try {
      stats = getEvaluationStats();
    } catch {
      /* ok */
    }
    try {
      const trend = getScoreTrend(10);
      if (trend.length > 0) {
        scoreTrend = trend.map((t) => ({ version: t.version_tag, score: t.overall_score }));
      }
    } catch {
      /* ok */
    }
    try {
      testCaseCount = listTestCases({ limit: 1000 }).length;
    } catch {
      /* ok */
    }
    try {
      versionCount = listEvolutionVersions().length;
    } catch {
      /* ok */
    }
    return { stats, scoreTrend, versionCount, testCaseCount };
  }

  /** Load comparison runs for arena view. */
  private _loadComparisonRuns(): EvolutionLabData['comparisonRuns'] {
    const result: NonNullable<EvolutionLabData['comparisonRuns']> = [];
    let colorIdx = 0;
    for (const selId of this.benchmarkSelectedRunIds) {
      try {
        const run = getBenchmarkRun(selId);
        if (!run) {
          continue;
        }
        const scores = listCategoryScores(selId);
        let presetName: string | undefined;
        if (run.metadata) {
          try {
            presetName = (JSON.parse(run.metadata) as { presetName?: string }).presetName;
          } catch {
            /* ok */
          }
        }
        result.push({
          id: selId,
          label: presetName || run.version_tag || selId.slice(0, 8),
          color: RUN_COLORS[colorIdx % RUN_COLORS.length],
          overallScore: run.overall_score,
          categoryScores: parseAndReAggregateScores(scores),
        });
        colorIdx++;
      } catch {
        /* run may have been deleted */
      }
    }
    return result;
  }

  /** Load versions tab data (git graph, timeline, inspector). */
  private _loadVersionsTabData(
    benchmarkRunsList: EvolutionLabData['benchmarkRuns']
  ): Pick<EvolutionLabData, 'versions' | 'mainCommits' | 'timelineEvents' | 'changedFiles'> {
    const timelineEvents: NonNullable<EvolutionLabData['timelineEvents']> = [];
    let versions: EvolutionLabData['versions'];
    let mainCommits: EvolutionLabData['mainCommits'];
    let changedFiles: EvolutionLabData['changedFiles'];

    try {
      mainCommits = buildMainCommitsWithScores(benchmarkRunsList);
    } catch {
      /* git log may fail */
    }
    try {
      const versionRows = listEvolutionVersions({ limit: 20 });
      versions = versionRows.map(mapEvolutionVersion);
      for (const v of versionRows) {
        timelineEvents.push(mapVersionToTimelineEvent(v));
      }
    } catch {
      /* table may not exist yet */
    }

    if (benchmarkRunsList) {
      for (const r of benchmarkRunsList) {
        timelineEvents.push({
          id: `bench_${r.id}`,
          type: 'benchmark',
          label: `Benchmark ${r.version_tag || r.profile}`,
          description: `Score: ${Math.round(r.overall_score)} (${r.passed_count}/${r.total_test_cases} passed)`,
          timestamp: r.timestamp,
          score: r.overall_score,
          status: r.overall_score >= 70 ? 'success' : 'failed',
        });
      }
    }
    timelineEvents.sort((a, b) => b.timestamp - a.timestamp);

    const inspectBranch = this.evolutionSelectedVersion || this.evolutionInspectedBranch;
    if (inspectBranch) {
      try {
        changedFiles = getChangedFilesForVersion(inspectBranch).map((p) => ({
          path: p,
          status: 'modified' as const,
        }));
      } catch {
        /* branch may not exist */
      }
    }

    return {
      versions,
      mainCommits,
      timelineEvents: timelineEvents.length > 0 ? timelineEvents : undefined,
      changedFiles,
    };
  }

  /** Load data tab data (traces, evaluations, suggestions). */
  private _loadDataTabData(): Pick<EvolutionLabData, 'traces' | 'tracesTotal' | 'evaluations' | 'suggestions'> {
    const subTab = this.evolutionDataSubTab;
    if (subTab === 'traces') {
      try {
        const traceRows = listTraces({ limit: 20, offset: this.tracesPage * 20 });
        return {
          tracesTotal: countTraces(),
          traces: traceRows.map((tr) => {
            const ev = getEvaluationByTraceId(tr.id);
            return {
              id: tr.id,
              timestamp: tr.timestamp,
              userMessage: tr.user_message,
              score: ev?.overall_score,
            };
          }),
        };
      } catch {
        return {};
      }
    }
    if (subTab === 'evaluations') {
      try {
        return {
          evaluations: listEvaluations({ limit: 50 }).map((e) => ({
            id: e.id,
            traceId: e.trace_id,
            timestamp: e.timestamp,
            score: e.overall_score,
            feedback: e.feedback,
          })),
        };
      } catch {
        return {};
      }
    }
    if (subTab === 'suggestions') {
      try {
        return {
          suggestions: listSuggestions({ limit: 50 }).map((s) => ({
            id: s.id,
            timestamp: s.timestamp,
            type: s.type,
            target: s.target,
            status: s.status,
            rationale: s.rationale,
          })),
        };
      } catch {
        return {};
      }
    }
    return {};
  }

  /**
   * Send an Evolution Lab page update to the client.
   */
  sendEvolutionLabUpdate(send: (msg: unknown) => void): void {
    const activeSend = this.getSend(send);
    if (this.currentView === 'system-agent') {
      this.sendSystemAgentUpdate(activeSend);
    } else if (this.currentView === 'evolution') {
      const labData = this.buildEvolutionLabData();
      const labPage = generateEvolutionLab(labData);
      sendAll(activeSend, labPage);
    }
  }

  /**
   * Send a System Agent page update to the client.
   */
  private sendSystemAgentUpdate(send: (msg: unknown) => void): void {
    const activeSend = this.getSend(send);
    if (this.currentView === 'system-agent') {
      const page = generateSystemAgentPage({
        chatMessages: this.systemAgentChatMessages,
        streaming: this.systemAgentStreaming,
        streamingContent: this.systemAgentStreamingContent,
      });
      sendAll(activeSend, page);
    }
  }

  // Throttled version to avoid flooding during concurrent benchmark progress updates.
  // Uses trailing-edge: always sends the most recent state after the throttle window.
  private _throttleTimer: ReturnType<typeof setTimeout> | null = null;
  private _throttlePendingSend: ((msg: unknown) => void) | null = null;
  private sendEvolutionLabUpdateThrottled(send: (msg: unknown) => void): void {
    this._throttlePendingSend = send;
    if (this._throttleTimer) {
      return;
    }
    // Send immediately on first call
    this.sendEvolutionLabUpdate(send);
    this._throttleTimer = setTimeout(() => {
      this._throttleTimer = null;
      // Flush any pending update that arrived during throttle window
      if (this._throttlePendingSend) {
        this.sendEvolutionLabUpdate(this._throttlePendingSend);
        this._throttlePendingSend = null;
      }
    }, 100);
  }

  /**
   * Load evolution data synchronously (DB queries are fast)
   */
  // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
  private loadEvolutionData() {
    const tabData = loadEvolutionTabData(this.evolutionTab, this.tracesPage);
    const externalProgress = loadEvolutionExternalProgress(this.evolutionTab);
    const versions = loadEvolutionVersionsList(this.evolutionTab);
    return {
      activeTab: this.evolutionTab,
      tracesPage: this.tracesPage,
      tracesTotal: tabData.tracesTotal ?? 0,
      ...tabData,
      externalProgress,
      versions,
      activeVersionBranch: this.activeVersionBranch,
    };
  }

  findFullBenchmarkRunId(shortId: string): string | null {
    const runs = listBenchmarkRuns({ limit: 100 });
    const found = runs.find((r) => r.id === shortId || r.id.startsWith(shortId));
    return found?.id || null;
  }

  sendBenchmarkRunModal(runId: string, send: (msg: unknown) => void): void {
    const run = getBenchmarkRun(runId);
    if (!run) {
      return;
    }
    const scores = listCategoryScores(runId);
    const sharpCategories = parseAndReAggregateScores(scores);
    const modal = generateBenchmarkRunDetailModal(
      {
        id: run.id,
        timestamp: run.timestamp,
        versionTag: run.version_tag,
        profile: run.profile,
        overallScore: run.overall_score,
        passedCount: run.passed_count,
        failedCount: run.failed_count,
        totalTestCases: run.total_test_cases,
        durationMs: run.duration_ms,
      },
      sharpCategories.map((s) => ({
        category: s.category,
        score: s.score,
        testCount: s.test_count,
        passedCount: s.passed_count,
        subComponents: s.subComponents,
      })),
      this.modalRadarMode
    );
    sendAll(send, modal);
  }

  /** Check benchmark preconditions. Returns a warning message string if blocked, or null if ok. */
  private checkBenchmarkPreConditions(modelConfig?: { modelId?: string }): string | null {
    const externalProgress = readBenchmarkProgress();
    if (externalProgress && externalProgress.source !== 'ui') {
      return t('evolution.externalBenchmarkRunning');
    }
    const targetModelId = modelConfig?.modelId || '__default__';
    for (const entry of this.runningBenchmarks.values()) {
      if (entry.modelId === targetModelId) {
        return t('evolution.modelAlreadyRunning');
      }
    }
    return null;
  }

  /** Create a BenchmarkRunner with the given config. */
  private createBenchmarkRunner(
    profile: 'quick' | 'full',
    trackingId: string,
    liveSend: () => (msg: unknown) => void,
    modelConfig?: {
      provider: string;
      modelId: string;
      apiKey?: string;
      baseUrl?: string;
      presetName?: string;
    }
  ): BenchmarkRunner {
    const agentApiKey = modelConfig?.apiKey || this.config.apiKey;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const agentProvider = (modelConfig?.provider || this.config.provider) as any;
    const agentModelId = modelConfig?.modelId || this.config.modelId;
    const agentBaseUrl = modelConfig?.baseUrl || this.config.baseUrl;
    const judgeConfig = getJudgeModel();
    const judgeApiKey = resolveBenchmarkModelApiKey(judgeConfig);
    const judgeBaseUrl = resolveBenchmarkModelBaseUrl(judgeConfig);

    return new BenchmarkRunner({
      agentCall: async (query: string, testCase) => {
        const { seedTestUser, createBenchmarkDataSource, getTestUserUuid, loadTestUserFixture } =
          await import('../evolution/test-user-seeder.js');
        const fixture = loadTestUserFixture(testCase.userUuid);
        seedTestUser(fixture);
        const dataSource = createBenchmarkDataSource(testCase.userUuid, testCase.healthOverrides);
        const testAgent = await createPHAAgent({
          apiKey: agentApiKey,
          provider: agentProvider,
          modelId: agentModelId,
          baseUrl: agentBaseUrl,
          userUuid: getTestUserUuid(testCase.userUuid),
          dataSource,
          sessionMessages: testCase.sessionMessages,
        });
        return withActivityTimeout(testAgent, () => testAgent.chatAndWaitWithTools(query));
      },
      llmCall: async (prompt: string) => {
        const { MockDataSource: JudgeMockDS } = await import('../data-sources/mock.js');
        const judgeAgent = await createPHAAgent({
          apiKey: judgeApiKey,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          provider: judgeConfig.provider as any,
          modelId: judgeConfig.modelId,
          baseUrl: judgeBaseUrl,
          dataSource: new JudgeMockDS(),
        });
        return withActivityTimeout(judgeAgent, () => judgeAgent.chatAndWait(prompt));
      },
      onProgress: (current, total, testCase) => {
        writeBenchmarkProgressForRun(trackingId, {
          running: true,
          source: 'ui',
          profile,
          current,
          total,
          category: testCase.category,
          startedAt: Date.now(),
          modelId: modelConfig?.modelId,
          presetName: modelConfig?.presetName,
          trackingId,
          pid: process.pid,
        });
        this.sendEvolutionLabUpdateThrottled(liveSend());
      },
      concurrency: getBenchmarkConcurrency(),
    });
  }

  async runBenchmarkAsync(
    profile: 'quick' | 'full',
    send: (msg: unknown) => void,
    modelConfig?: {
      provider: string;
      modelId: string;
      apiKey?: string;
      baseUrl?: string;
      presetName?: string;
    }
  ): Promise<void> {
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const liveSend = () => this.getSend(send);

    const blockMsg = this.checkBenchmarkPreConditions(modelConfig);
    if (blockMsg) {
      sendAll(liveSend(), generateToast(blockMsg, 'warning'));
      return;
    }

    const targetModelId = modelConfig?.modelId || '__default__';
    const trackingId = crypto.randomUUID();
    this.runningBenchmarks.set(trackingId, {
      modelId: targetModelId,
      presetName: modelConfig?.presetName,
      startedAt: Date.now(),
    });
    writeBenchmarkProgressForRun(trackingId, {
      running: true,
      source: 'ui',
      profile,
      current: 0,
      total: 0,
      category: '',
      startedAt: Date.now(),
      modelId: modelConfig?.modelId,
      presetName: modelConfig?.presetName,
      trackingId,
      pid: process.pid,
    });
    this.sendEvolutionLabUpdate(liveSend());

    try {
      const runner = this.createBenchmarkRunner(profile, trackingId, liveSend, modelConfig);
      await runner.seedTestCases();
      const modelOverride = modelConfig
        ? {
            provider: modelConfig.provider,
            modelId: modelConfig.modelId,
            presetName: modelConfig.presetName,
          }
        : undefined;
      await runner.run({ profile, modelOverride });
      if (this.currentView === 'evolution') {
        this.sendEvolutionLabUpdate(liveSend());
      } else {
        await this.handleNavigate('settings/evolution', liveSend());
      }
    } catch (error) {
      sendAll(
        liveSend(),
        generateToast(`Benchmark failed: ${error instanceof Error ? error.message : String(error)}`, 'error')
      );
    } finally {
      this.runningBenchmarks.delete(trackingId);
      clearBenchmarkProgressForRun(trackingId);
      this.sendEvolutionLabUpdate(liveSend());
    }
  }

  async runDiagnoseAsync(send: (msg: unknown) => void): Promise<void> {
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const liveSend = () => this.getSend(send);

    // Show diagnosing toast
    const startToast = generateToast(t('evolution.diagnosing'), 'info');
    sendAll(liveSend(), startToast);

    try {
      const { diagnose } = await import('../evolution/diagnose.js');

      // Create dedicated judge agent for diagnose evaluation
      const djConfig = getJudgeModel();
      const djApiKey = resolveBenchmarkModelApiKey(djConfig);
      const djBaseUrl = resolveBenchmarkModelBaseUrl(djConfig);
      const { MockDataSource: DiagMockDS } = await import('../data-sources/mock.js');
      const diagnoseJudge = await createPHAAgent({
        apiKey: djApiKey,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        provider: djConfig.provider as any,
        modelId: djConfig.modelId,
        baseUrl: djBaseUrl,
        dataSource: new DiagMockDS(),
      });

      const result = await diagnose({
        profile: 'quick',
        runnerConfig: {
          agentCall: async (query: string, testCase) => {
            const { seedTestUser, createBenchmarkDataSource, getTestUserUuid, loadTestUserFixture } =
              await import('../evolution/test-user-seeder.js');
            const fixture = loadTestUserFixture(testCase.userUuid);
            seedTestUser(fixture);
            const dataSource = createBenchmarkDataSource(testCase.userUuid, testCase.healthOverrides);
            const testAgent = await createPHAAgent({
              apiKey: djApiKey,
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              provider: djConfig.provider as any,
              modelId: djConfig.modelId,
              baseUrl: djBaseUrl,
              userUuid: getTestUserUuid(testCase.userUuid),
              dataSource,
              sessionMessages: testCase.sessionMessages,
            });
            return withActivityTimeout(testAgent, () => testAgent.chatAndWaitWithTools(query));
          },
          llmCall: async (prompt: string) => {
            if (typeof diagnoseJudge.reset === 'function') {
              diagnoseJudge.reset();
            }
            return withActivityTimeout(diagnoseJudge, () => diagnoseJudge.chatAndWait(prompt));
          },
        },
        onProgress: (msg: string) => {
          const progress = generateToast(msg, 'info');
          sendAll(liveSend(), progress);
        },
      });

      // Show results
      const completeMsg =
        result.weaknesses.length > 0
          ? `${t('evolution.diagnoseComplete')}: ${result.weaknesses.length} ${t('evolution.weakCategories').toLowerCase()}`
          : t('evolution.noWeaknesses');
      const toast = generateToast(completeMsg, result.weaknesses.length > 0 ? 'warning' : 'success');
      sendAll(liveSend(), toast);

      // Refresh evolution page
      if (this.currentView === 'evolution') {
        this.sendEvolutionLabUpdate(liveSend());
      } else {
        await this.handleNavigate('settings/evolution', liveSend());
      }
    } catch (error) {
      const toast = generateToast(
        `Diagnose failed: ${error instanceof Error ? error.message : String(error)}`,
        'error'
      );
      sendAll(liveSend(), toast);
    }
  }

  /**
   * Get or create the current assistant message in chatMessages.
   */
  // ========================================================================
  // Legacy Chat SSE — External API endpoint (/api/legacy-chat)
  // ========================================================================

  async handleLegacyChatSSE(
    content: string,
    writer: WritableStreamDefaultWriter<Uint8Array>,
    encoder: TextEncoder,
    eventObserver?: (event: unknown) => void
  ): Promise<void> {
    let streamClosed = false;
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const safeWrite = (data: string) => {
      if (streamClosed) {
        return;
      }
      try {
        writer.write(encoder.encode(data)).catch(() => {
          streamClosed = true;
        });
      } catch {
        streamClosed = true;
      }
    };
    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const safeClose = () => {
      if (streamClosed) {
        return;
      }
      streamClosed = true;
      try {
        writer.close().catch(() => {});
      } catch {
        // ignore
      }
    };

    // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
    const sseSend = (event: LegacySSEEvent) => {
      safeWrite(`data: ${JSON.stringify(event)}\n\n`);
    };

    try {
      const agent = await this.getLegacyChatAgent();
      const adapter = new LegacyProtocolAdapter(sseSend);

      const unsubscribe = agent.subscribe((event) => {
        try {
          eventObserver?.(event);
        } catch {
          /* noop */
        }
        adapter.handleAgentEvent(event);
      });

      try {
        const skillHint = agent.getSkillHint();
        if (skillHint) {
          await agent.chatWithSkill(content, skillHint);
        } else {
          await agent.chatWithSkill(content, 'legacy-streaming');
        }
        await agent.getAgent().waitForIdle();

        // Ensure agent_end was processed — force it if needed
        adapter.handleAgentEvent({ type: 'agent_end' });
      } finally {
        unsubscribe();
      }
    } catch (error) {
      const isAbort = error instanceof Error && (error.name === 'AbortError' || /abort/i.test(error.message));
      if (!isAbort) {
        sseSend({
          event: 'data',
          content: `Error: ${error instanceof Error ? error.message : String(error)}`,
        });
        sseSend({ event: 'finish' });
      }
    } finally {
      safeClose();
    }
  }

  private getOrCreateAssistantMsg(): PartsChatMessage {
    const isLegacy = this._chatChannel === 'legacy';
    const messages = isLegacy ? this.legacyChatMessages : this.chatMessages;
    const currentMsgId = isLegacy ? this.legacyChatCurrentAssistantMsgId : this.currentAssistantMsgId;

    if (currentMsgId) {
      const existing = messages.find((m) => m.id === currentMsgId);
      if (existing) {
        return existing;
      }
    }
    const msg: PartsChatMessage = {
      id: crypto.randomUUID(),
      role: 'assistant',
      parts: [],
    };
    messages.push(msg);
    if (isLegacy) {
      this.legacyChatCurrentAssistantMsgId = msg.id;
    } else {
      this.currentAssistantMsgId = msg.id;
    }
    return msg;
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private handleAgentEvent(event: any, send: (msg: unknown) => void): void {
    try {
      dispatchAgentEvent(this, event, send);
    } catch (err) {
      log.error('handleAgentEvent uncaught error', { eventType: event?.type, error: err });
    }
  }
}

/** Normalize a benchmark score to 0-1 range (scores >1 are assumed to be percentages). */
function normalizeScore(score: number): number {
  return score <= 1 ? score : score / 100;
}

// ── buildEvolutionLabData helpers (pure functions) ──────────────────────

/** Determine run status from duration_ms: -1=failed, >0=completed, else running. */
function getRunStatus(durationMs: number | null | undefined): 'running' | 'completed' | 'failed' {
  if (durationMs != null && durationMs < 0) {
    return 'failed';
  }
  if (durationMs && durationMs > 0) {
    return 'completed';
  }
  return 'running';
}

function mapBenchmarkRun(
  r: any,
  benchmarkModelsCfg: Record<string, { label?: string }>
): NonNullable<EvolutionLabData['benchmarkRuns']>[number] {
  let modelId: string | undefined;
  let presetName: string | undefined;
  if (r.metadata) {
    try {
      const meta = JSON.parse(r.metadata);
      modelId = meta.modelId;
      const rawPreset = meta.presetName as string | undefined;
      presetName = rawPreset && benchmarkModelsCfg[rawPreset]?.label ? benchmarkModelsCfg[rawPreset].label : rawPreset;
    } catch {
      /* ok */
    }
  }
  return {
    id: r.id,
    timestamp: r.timestamp,
    version_tag: r.version_tag || '',
    overall_score: r.overall_score,
    passed_count: r.passed_count,
    failed_count: r.failed_count,
    total_test_cases: r.total_test_cases,
    profile: r.profile,
    duration_ms: r.duration_ms || 0,
    modelId,
    presetName,
    status: getRunStatus(r.duration_ms),
  };
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function mapEvolutionVersion(v: any): NonNullable<EvolutionLabData['versions']>[number] {
  return {
    id: v.id,
    branchName: v.branch_name,
    parentBranch: v.parent_branch || 'main',
    status: v.status || 'active',
    triggerMode: v.trigger_mode || '',
    triggerRef: v.trigger_ref || '',
    scoreDelta: v.score_delta,
    filesChanged: v.files_changed ? JSON.parse(v.files_changed) : [],
    createdAt: v.created_at,
  };
}

const VERSION_EVENT_TYPE_MAP: Record<string, 'branch' | 'merge' | 'revert'> = {
  merged: 'merge',
  abandoned: 'revert',
};
const VERSION_STATUS_MAP: Record<string, 'success' | 'failed' | 'active' | 'pending'> = {
  merged: 'success',
  abandoned: 'failed',
  active: 'active',
};

function mapVersionToTimelineEvent(v: any): NonNullable<EvolutionLabData['timelineEvents']>[number] {
  return {
    id: `ver_${v.id}`,
    type: VERSION_EVENT_TYPE_MAP[v.status || ''] ?? 'branch',
    label: v.branch_name,
    description: v.trigger_mode || undefined,
    timestamp: v.created_at,
    branch: v.branch_name,
    status: VERSION_STATUS_MAP[v.status || ''] ?? 'pending',
  };
}

function buildMainCommitsWithScores(
  benchmarkRunsList: EvolutionLabData['benchmarkRuns']
): NonNullable<EvolutionLabData['mainCommits']> {
  const gitCommits = getGitLog({ limit: 15, branch: 'main' });
  const completedRuns = (benchmarkRunsList || []).filter((r) => r.status === 'completed' && r.overall_score > 0);
  const usedRunIds = new Set<string>();

  return gitCommits.map((c) => {
    const commitTime = new Date(c.date).getTime();
    let matchedRun = completedRuns.find(
      (r) => !usedRunIds.has(r.id) && (r.version_tag === c.shortHash || r.version_tag?.includes(c.shortHash))
    );
    if (!matchedRun) {
      let bestDelta = Infinity;
      for (const r of completedRuns) {
        if (usedRunIds.has(r.id)) {
          continue;
        }
        const delta = r.timestamp - commitTime;
        if (delta >= 0 && delta < 3600000 && delta < bestDelta) {
          bestDelta = delta;
          matchedRun = r;
        }
      }
    }
    if (matchedRun) {
      usedRunIds.add(matchedRun.id);
    }
    return {
      hash: c.hash,
      shortHash: c.shortHash,
      message: c.message,
      date: c.date,
      benchmarkScore: matchedRun ? normalizeScore(matchedRun.overall_score) : null,
      benchmarkTag: matchedRun?.version_tag || undefined,
    };
  });
}

