// ---- Route Helpers ----

/** Extract user ID from request cookie (pha_uid preferred, pha_user_id legacy fallback). */
function extractUserId(req: Request): string | undefined {
  const cookieHeader = req.headers.get('cookie') || '';
  const match = cookieHeader.match(/pha_uid=([^;]+)/) || cookieHeader.match(/pha_user_id=([^;]+)/);
  return match ? match[1] : undefined;
}

/** Get or create a GatewaySession from the sessions map. */
function getOrCreateSessionFromMap(
  sessions: Map<string, GatewaySession>,
  config: GatewayConfig,
  userId?: string
): GatewaySession {
  const key = userId || '__anonymous__';
  let session = sessions.get(key);
  if (!session) {
    session = userId ? new GatewaySession(config, userId) : new GatewaySession(config);
    sessions.set(key, session);
  }
  return session;
}

/** Create an SSE stream response for a chat handler. */
function sseStreamResponse(session: GatewaySession, content: string, handler: 'chat' | 'legacy-chat'): Response {
  const { readable, writable } = new TransformStream<Uint8Array>();
  const writer = writable.getWriter();
  const encoder = new TextEncoder();
  const fn = handler === 'chat' ? session.handleChatSSE.bind(session) : session.handleLegacyChatSSE.bind(session);
  fn(content, writer, encoder).catch(() => {
    try {
      writer.close().catch(() => {});
    } catch {
      /* noop */
    }
  });
  return new Response(readable, { headers: SSE_HEADERS });
}

/** Inject basePath into index.html so frontend knows the prefix. */
async function serveIndexWithBasePath(webDir: string, basePath: string): Promise<Response | null> {
  const indexFile = Bun.file(`${webDir}/index.html`);
  if (!(await indexFile.exists())) {
    return null;
  }
  if (!basePath) {
    return new Response(indexFile, { headers: { 'Content-Type': 'text/html' } });
  }
  let html = await indexFile.text();
  html = html.replaceAll('"/assets/', `"${basePath}/assets/`);
  html = html.replaceAll("'/assets/", `'${basePath}/assets/`);
  html = html.replace('<head>', `<head><script>window.__PHA_BASE_PATH__="${basePath}";</script>`);
  return new Response(html, { headers: { 'Content-Type': 'text/html' } });
}

/** Run one-time startup tasks (migration, seed, cleanup). */
async function runStartupTasks(): Promise<void> {
  migrateStateDir();
  try {
    const { seedAllTestUsers } = await import('../evolution/test-user-seeder.js');
    seedAllTestUsers();
  } catch {
    /* optional */
  }
  cleanupOldLlmLogs();
  cleanupOldSessions();
  cleanupOldMemoryLogs();
  const interrupted = markInterruptedBenchmarkRuns();
  if (interrupted > 0) {
    log.info('Cleaned up interrupted benchmark runs', { count: interrupted });
  }
  clearBenchmarkProgress();
  clearAllUiBenchmarkProgress();
}

/** Load plugins and start skills hot-reload watcher + proactive engine. */
async function initPluginsAndWatchers(sseManager: SSEConnectionManager): Promise<void> {
  const phaConfig = loadConfig();
  if (phaConfig.plugins?.enabled !== false) {
    try {
      const pluginRegistry = await loadPlugins({
        workspaceDir: getStateDir(),
        extraPaths: phaConfig.plugins?.paths,
        pluginConfigs: phaConfig.plugins?.entries,
      });
      const loaded = pluginRegistry.plugins.filter((p) => p.status === 'loaded');
      if (loaded.length > 0) {
        log.info(`${loaded.length} plugin(s) loaded`, { plugins: loaded.map((p) => p.id) });
      }
    } catch (err) {
      log.warn('Plugin loading failed', { error: err });
    }
  }
  const skillsWatchDir = getSkillsDir();
  if (existsSync(skillsWatchDir)) {
    let skillDebounce: ReturnType<typeof setTimeout> | null = null;
    chokidar
      .watch(skillsWatchDir, {
        ignoreInitial: true,
        awaitWriteFinish: { stabilityThreshold: 500, pollInterval: 100 },
      })
      .on('all', (event, changedPath) => {
        if (!changedPath.endsWith('SKILL.md')) {
          return;
        }
        if (skillDebounce) {
          clearTimeout(skillDebounce);
        }
        skillDebounce = setTimeout(() => {
          skillDebounce = null;
          log.info('Skill file changed, notifying clients', { event, path: changedPath });
          for (const msg of generateToast('技能文件已更新', 'info')) {
            sseManager.broadcast(msg);
          }
        }, 1000);
      });
  }
  const { ProactiveTriggerEngine } = await import('../proactive/trigger-engine.js');
  const triggerEngine = new ProactiveTriggerEngine(sseManager, {
    intervalMinutes: phaConfig.proactive?.checkIntervalMinutes ?? 5,
  });
  if (phaConfig.proactive?.enabled !== false) {
    triggerEngine.start();
  }
}

/** Install process exit handlers for hooks and crash resilience. */
function installProcessHandlers(port: number): void {
  const hr = getGlobalHookRunner();
  if (hr) {
    hr.runGatewayStart({ port }, { port }).catch((err) => log.warn('Hook gateway_start error', { error: err }));
  }
  // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
  const handleExit = () => {
    const runner = getGlobalHookRunner();
    if (runner) {
      runner.runGatewayStop({ reason: 'process_exit' }, { port }).catch(() => {});
    }
  };
  process.on('SIGINT', handleExit);
  process.on('SIGTERM', handleExit);
  process.on('uncaughtException', (err) => {
    log.error('Uncaught exception (process kept alive)', {
      error: err instanceof Error ? err.message : String(err),
      stack: err instanceof Error ? err.stack : new Error().stack,
      type: typeof err,
    });
  });
  process.on('unhandledRejection', (reason) => {
    log.error('Unhandled rejection (process kept alive)', {
      error: reason instanceof Error ? reason.message : String(reason),
      stack: reason instanceof Error ? reason.stack : new Error().stack,
      type: typeof reason,
    });
  });
}

// ---- Individual route handlers (used by dispatchRoute) ----

/** Context shared by all route handlers. */
interface FetchContext {
  config: GatewayConfig;
  sessions: Map<string, GatewaySession>;
  sseManager: SSEConnectionManager;
  port: number;
  basePath: string;
  webDir?: string;
  app: Hono;
}

/** Handle POST /api/ag-ui — AG-UI SSE chat. */
async function handleAgUi(req: Request, ctx: FetchContext): Promise<Response> {
  const body = (await req.json()) as {
    thread_id?: string;
    messages?: Array<{ role: string; content: string }>;
  };
  const userMessages = body.messages || [];
  const lastUserMsg = userMessages.filter((m) => m.role === 'user').pop();
  if (!lastUserMsg?.content) {
    return jsonError('No user message', 400);
  }
  const key = body.thread_id || crypto.randomUUID();
  const session = getOrCreateSessionFromMap(ctx.sessions, ctx.config, key);
  return sseStreamResponse(session, lastUserMsg.content, 'chat');
}

/** Handle POST /api/legacy-chat — Legacy chat SSE. */
async function handleLegacyChat(req: Request, ctx: FetchContext): Promise<Response> {
  const body = (await req.json()) as { message?: string; user_id?: string; session_id?: string };
  if (!body.message) {
    return jsonError('No message', 400);
  }
  const key = body.user_id || body.session_id || crypto.randomUUID();
  const session = getOrCreateSessionFromMap(ctx.sessions, ctx.config, key);
  return sseStreamResponse(session, body.message, 'legacy-chat');
}

/** Build an event observer for /api/query that logs tool dispatch and agent lifecycle with sn. */
function buildQueryEventObserver(sn: string | undefined): (event: unknown) => void {
  const requestStart = Date.now();
  let currentToolName: string | null = null;
  let currentToolStart = 0;

  // Accumulate tool_calls and tool_results across the entire query
  const toolCallsList: string[] = [];
  const toolResultsList: Array<{ tool: string; result: unknown }> = [];

  // Subscribe to LLM logs to capture the final prompt (last LLM request during this query).
  // Uses a window-based approach: subscribe at observer creation, unsubscribe at agent_end.
  let lastLlmMessages: unknown = null;
  const unsubscribeLlm = subscribeToLlmLogs((pair) => {
    // Keep overwriting so we always have the LAST LLM call (which produces the final answer)
    lastLlmMessages = (pair.requestData as Record<string, unknown>)?.messages ?? null;
  });

  return (event: unknown): void => {
    const e = event as {
      type?: string;
      toolName?: string;
      isError?: boolean;
      result?: unknown;
    };

    switch (e.type) {
      case 'tool_execution_start':
        currentToolName = e.toolName ?? null;
        currentToolStart = Date.now();
        toolCallsList.push(e.toolName ?? 'unknown');
        log.info('[query] tool.start', {
          sn,
          phase: 'tool_start',
          tool: e.toolName,
          label: TOOL_LABELS[e.toolName ?? ''] ?? '正在查询数据',
        });
        break;

      case 'tool_execution_end': {
        const durationMs = currentToolName ? Date.now() - currentToolStart : undefined;
        toolResultsList.push({ tool: e.toolName ?? 'unknown', result: e.result });
        const resultStr = e.result != null ? JSON.stringify(e.result).slice(0, 1000) : undefined;
        log.info('[query] tool.end', {
          sn,
          phase: 'tool_end',
          tool: e.toolName,
          durationMs,
          isError: e.isError ?? false,
          result: resultStr,
        });
        currentToolName = null;
        break;
      }

      case 'agent_end': {
        unsubscribeLlm();
        const totalDurationMs = Date.now() - requestStart;
        log.info('[query] agent.end', { sn, phase: 'agent_end', totalDurationMs });
        // Log summary with tool_calls, tool_results, and final_prompt in one entry
        log.info('[query] summary', {
          sn,
          phase: 'summary',
          tool_calls: toolCallsList.join(', '),
          tool_results: toolResultsList,
          final_prompt: lastLlmMessages,
        });
        break;
      }

      default:
        break;
    }
  };
}

/** Send an SSE error + finish frame and close the writer. Returns the string used as phase for logging. */
function sseErrorAndClose(
  sseSendRaw: (obj: unknown) => void,
  writer: WritableStreamDefaultWriter<Uint8Array>,
  sn: string | undefined,
  phase: string,
  errorMsg: string
): void {
  log.warn('[query] error', { sn, phase, error: errorMsg });
  sseSendRaw({ event: 'error', content: errorMsg });
  sseSendRaw({ event: 'finish' });
  writer.close().catch(() => {});
}

/** Handle client_credentials grant type for /api/query. */
async function handleQueryClientCredentials(
  ctx: FetchContext,
  params: { sn?: string; Authorization: string; query: string; uid?: string; client_id?: string },
  writer: WritableStreamDefaultWriter<Uint8Array>,
  encoder: TextEncoder,
  sseSendRaw: (obj: unknown) => void,
  eventObserver: (event: unknown) => void
): Promise<string> {
  const { sn, uid, client_id, Authorization, query } = params;
  if (!uid || !client_id) {
    sseErrorAndClose(sseSendRaw, writer, sn, 'validation', 'Missing required fields: uid, client_id');
    return 'validation';
  }

  ensureUserDir(uid);
  const innerDataSource = createInnerDataSourceForUser(uid, Authorization, uid, client_id);
  const session = new GatewaySession(ctx.config, uid, innerDataSource);
  log.info('[query] session', {
    sn,
    phase: 'session',
    userId: uid,
    sessionId: session.getSessionId(),
    mode: 'client_credentials',
  });

  await session.handleLegacyChatSSE(query, writer, encoder, eventObserver);
  return 'agent';
}

/** Handle refresh_token grant type for /api/query. */
async function handleQueryRefreshToken(
  ctx: FetchContext,
  params: { sn?: string; Authorization: string; query: string },
  writer: WritableStreamDefaultWriter<Uint8Array>,
  encoder: TextEncoder,
  sseSendRaw: (obj: unknown) => void,
  eventObserver: (event: unknown) => void
): Promise<string> {
  const { sn, Authorization, query } = params;
  const fullConfig = loadConfig();
  const huaweiConfig = fullConfig.dataSources.huawei;
  if (!huaweiConfig?.clientId || !huaweiConfig?.clientSecret) {
    sseErrorAndClose(sseSendRaw, writer, sn, 'auth', 'Huawei credentials not configured');
    return 'auth';
  }

  log.info('[query] auth.start', { sn, phase: 'auth_start', grant_type: 'refresh_token' });

  let userId: string;
  try {
    const authStart = Date.now();
    const {
      tokenData,
      userId: resolvedUid,
      uid,
    } = await huaweiAuth.refreshTokenAndGetUserId(Authorization, huaweiConfig.clientId, huaweiConfig.clientSecret);
    userId = resolvedUid;
    getUserStore().saveToken(userId, tokenData, uid);
    log.info('[query] auth.success', {
      sn,
      phase: 'auth_success',
      userId,
      durationMs: Date.now() - authStart,
      tokenExpiry: tokenData.expiresAt,
    });
  } catch (e) {
    log.error('[query] auth.failed', { sn, phase: 'auth_failed', error: String(e) });
    sseErrorAndClose(
      sseSendRaw,
      writer,
      sn,
      'auth_failed',
      `Token refresh failed: ${e instanceof Error ? e.message : String(e)}`
    );
    return 'auth';
  }

  ensureUserDir(userId);
  const session = new GatewaySession(ctx.config, userId);
  log.info('[query] session', {
    sn,
    phase: 'session',
    userId,
    sessionId: session.getSessionId(),
    mode: 'refresh_token',
  });

  await session.handleLegacyChatSSE(query, writer, encoder, eventObserver);
  return 'agent';
}

/** Handle POST /api/query — 边想边搜 SSE (refresh_token or client_credentials). */
async function handleQuery(req: Request, ctx: FetchContext): Promise<Response> {
  const { readable, writable } = new TransformStream<Uint8Array>();
  const writer = writable.getWriter();
  const encoder = new TextEncoder();
  const requestStart = Date.now();

  const sseSendRaw = (obj: unknown): void => {
    try {
      writer.write(encoder.encode(`data: ${JSON.stringify(obj)}\n\n`)).catch(() => {});
    } catch {
      /* noop */
    }
  };

  (async () => {
    let sn: string | undefined;
    let phase = 'parse';
    try {
      const body = (await req.json()) as {
        grant_type?: string;
        Authorization?: string;
        query?: string;
        sn?: string;
        uid?: string;
        client_id?: string;
      };

      const { grant_type = 'refresh_token', Authorization, query, uid, client_id } = body;
      sn = body.sn;

      // Log request params (mask auth token, keep first 6 chars for tracing)
      log.info('[query] request', {
        sn,
        phase: 'request',
        grant_type,
        query,
        uid,
        client_id,
        auth_prefix: Authorization ? `${Authorization.slice(0, 6)}...` : undefined,
      });

      if (!Authorization || !query) {
        sseErrorAndClose(sseSendRaw, writer, sn, 'validation', 'Missing required fields: Authorization, query');
        return;
      }

      const eventObserver = buildQueryEventObserver(sn);
      const params = { sn, Authorization, query, uid, client_id };

      phase =
        grant_type === 'client_credentials'
          ? await handleQueryClientCredentials(ctx, params, writer, encoder, sseSendRaw, eventObserver)
          : await handleQueryRefreshToken(ctx, params, writer, encoder, sseSendRaw, eventObserver);

      log.info('[query] done', {
        sn,
        phase: 'done',
        totalDurationMs: Date.now() - requestStart,
      });
    } catch (e) {
      log.error('[query] error', {
        sn,
        phase,
        error: String(e),
        totalDurationMs: Date.now() - requestStart,
      });
      try {
        sseSendRaw({ event: 'error', content: String(e) });
        sseSendRaw({ event: 'finish' });
      } catch {
        /* noop */
      }
      writer.close().catch(() => {});
    }
  })();

  return new Response(readable, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      Connection: 'keep-alive',
      'Access-Control-Allow-Origin': '*',
    },
  });
}

/** Handle POST /api/a2ui/init — Create/resume session. */
async function handleA2UIInit(req: Request, ctx: FetchContext): Promise<Response> {
  const body = (await req.json().catch(() => ({}))) as { uuid?: string; view?: string };
  const userId = body.uuid || extractUserId(req);
  const session = getOrCreateSessionFromMap(ctx.sessions, ctx.config, userId);
  const updates = await session.getFullPageState(body.view);
  const headers: Record<string, string> = { ...JSON_HEADERS };
  if (userId) {
    const expires = new Date();
    expires.setFullYear(expires.getFullYear() + 1);
    headers['Set-Cookie'] =
      `pha_session_id=${session.getSessionId()}; Path=/; Expires=${expires.toUTCString()}; SameSite=Strict`;
  }
  return new Response(JSON.stringify({ sessionId: session.getSessionId(), uid: session.userUuid, updates }), {
    headers,
  });
}

/** Handle POST /api/a2ui/action — User actions and navigation. */
async function handleA2UIAction(req: Request, ctx: FetchContext): Promise<Response> {
  const body = (await req.json()) as {
    type: string;
    action?: string;
    payload?: Record<string, unknown>;
    view?: string;
    sessionId?: string;
  };
  const session = getOrCreateSessionFromMap(ctx.sessions, ctx.config, extractUserId(req));
  const result = await session.handleHTTPRequest(body);
  return new Response(JSON.stringify(result), { headers: JSON_HEADERS });
}

/** Handle GET /api/a2ui/events — SSE long-lived connection. */
function handleA2UIEvents(req: Request, ctx: FetchContext): Response {
  const userId = extractUserId(req);
  const session = getOrCreateSessionFromMap(ctx.sessions, ctx.config, userId);
  const result = ctx.sseManager.createConnection(session.getSessionId());
  if (!result) {
    const encoder = new TextEncoder();
    return new Response(encoder.encode(`retry: 5000\ndata: {"type":"throttled"}\n\n`), {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Access-Control-Allow-Origin': '*',
      },
    });
  }
  const { readable, connection } = result;
  connection.sendRetry(3000);
  session.setSend((msg) => {
    ctx.sseManager.send(session.getSessionId(), msg);
  });
  const lastEventId = req.headers.get('Last-Event-ID');
  if (lastEventId) {
    for (const event of ctx.sseManager.replayFrom(session.getSessionId(), parseInt(lastEventId, 10))) {
      connection.send(JSON.parse(event.data), event.id);
    }
  }
  const hookRunner = getGlobalHookRunner();
  if (hookRunner) {
    hookRunner
      .runSessionStart({ sessionId: session.getSessionId() }, { sessionId: session.getSessionId() })
      .catch((err) => log.warn('Hook session_start error', { error: err }));
  }
  return new Response(readable, { headers: SSE_HEADERS });
}

/** Handle POST /api/mcp — MCP JSON-RPC 2.0. */
async function handleMCP(req: Request): Promise<Response> {
  const body = await req.json();
  const response = await handleMCPRequest(body);
  if (!response) {
    return new Response(null, { status: 204 });
  }
  return new Response(JSON.stringify(response), { headers: JSON_HEADERS });
}

/** Handle POST /api/a2a — A2A JSON-RPC 2.0 task management. */
async function handleA2A(req: Request, ctx: FetchContext): Promise<Response> {
  const body = await req.json();
  const response = await handleA2ARequest(body, async (_taskId, message) => {
    const session = new GatewaySession(ctx.config);
    ctx.sessions.set(_taskId, session);
    try {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const agent = await (session as any).getAgent();
      return await agent.chatAndWait(message);
    } finally {
      ctx.sessions.delete(_taskId);
    }
  });
  return new Response(JSON.stringify(response), { headers: JSON_HEADERS });
}

// ---- Route dispatch (used by fetch) ----

/** Route table entry: handler function + error handler type. */
type PostRouteHandler = (req: Request, ctx: FetchContext) => Promise<Response>;
type PostRouteEntry = { handler: PostRouteHandler; errorHandler: 'json' | 'jsonrpc' | 'none' };

/** POST route table — maps pathname to handler + error style. */
const POST_ROUTES: Record<string, PostRouteEntry> = {
  '/api/ag-ui': { handler: handleAgUi, errorHandler: 'json' },
  '/api/legacy-chat': { handler: handleLegacyChat, errorHandler: 'json' },
  '/api/query': { handler: handleQuery, errorHandler: 'none' },
  '/api/a2ui/init': { handler: handleA2UIInit, errorHandler: 'json' },
  '/api/a2ui/action': { handler: handleA2UIAction, errorHandler: 'json' },
  '/api/mcp': { handler: (req) => handleMCP(req), errorHandler: 'jsonrpc' },
  '/api/a2a': { handler: handleA2A, errorHandler: 'jsonrpc' },
};

/** Dispatch POST API routes. Returns null if no match. */
async function dispatchPostRoute(pathname: string, req: Request, ctx: FetchContext): Promise<Response | null> {
  const route = POST_ROUTES[pathname];
  if (!route) {
    return null;
  }

  if (route.errorHandler === 'none') {
    return route.handler(req, ctx);
  }

  try {
    return await route.handler(req, ctx);
  } catch (e) {
    return route.errorHandler === 'jsonrpc' ? jsonRpcParseError() : jsonError(e);
  }
}

/** Dispatch GET API routes. Returns null if no match. */
function dispatchGetRoute(pathname: string, req: Request, ctx: FetchContext): Response | null {
  if (pathname === '/api/a2ui/events') {
    return handleA2UIEvents(req, ctx);
  }
  if (pathname === '/.well-known/agent.json') {
    return new Response(JSON.stringify(generateAgentCard(ctx.port, ctx.basePath)), {
      headers: JSON_HEADERS,
    });
  }
  return null;
}

/** Dispatch a request to the appropriate route handler. Returns null if no match. */
async function dispatchRoute(pathname: string, req: Request, ctx: FetchContext): Promise<Response | null> {
  if (req.method === 'POST') {
    return dispatchPostRoute(pathname, req, ctx);
  }
  if (req.method === 'GET') {
    return dispatchGetRoute(pathname, req, ctx);
  }
  return null;
}

/** Try to serve a static file or SPA fallback from webDir. Returns null if not found. */
async function tryServeStatic(pathname: string, webDir: string, basePath: string): Promise<Response | null> {
  let filePath = pathname;
  if (filePath === '/' || filePath === '') {
    filePath = '/index.html';
  }
  if (filePath === '/index.html') {
    const resp = await serveIndexWithBasePath(webDir, basePath);
    if (resp) {
      return resp;
    }
  }
  const file = Bun.file(webDir + filePath);
  if (await file.exists()) {
    return new Response(file, { headers: { 'Content-Type': getContentType(filePath) } });
  }
  if (
    !filePath.startsWith('/api') &&
    !filePath.startsWith('/mcp') &&
    !filePath.startsWith('/health') &&
    !filePath.startsWith('/auth')
  ) {
    return serveIndexWithBasePath(webDir, basePath);
  }
  return null;
}

/**
 * Start the Gateway server with Bun
 */
export async function startGateway(
  config: GatewayConfig & { webDir?: string } = {}
): Promise<ReturnType<typeof Bun.serve>> {
  const host = config.host ?? '0.0.0.0';
  const port = config.port ?? 8000;
  const basePath = (config.basePath || '').replace(/\/+$/, '');
  const app = createGatewayApp();
  const sessions = new Map<string, GatewaySession>();
  const sseManager = new SSEConnectionManager();
  const webDir = config.webDir;

  await runStartupTasks();
  await initPluginsAndWatchers(sseManager);

  const ctx: FetchContext = { config, sessions, sseManager, port, basePath, webDir, app };

  const server = Bun.serve({
    hostname: host,
    port,
    idleTimeout: 255,
    async fetch(req, _server) {
      let pathname = new URL(req.url).pathname;
      if (basePath) {
        if (!pathname.startsWith(`${basePath}/`) && pathname !== basePath) {
          return new Response('Not Found', { status: 404 });
        }
        pathname = pathname.slice(basePath.length) || '/';
      }
      const routeResponse = await dispatchRoute(pathname, req, ctx);
      if (routeResponse) {
        return routeResponse;
      }
      if (webDir) {
        const staticResp = await tryServeStatic(pathname, webDir, basePath);
        if (staticResp) {
          return staticResp;
        }
      }
      if (basePath) {
        const stripped = new URL(req.url);
        stripped.pathname = pathname;
        return app.fetch(new Request(stripped.toString(), req));
      }
      return app.fetch(req);
    },
  });

  const displayHost = host === '0.0.0.0' ? 'localhost' : host;
  log.info(`PHA Gateway running at http://${displayHost}:${port}${basePath}`);
  log.info(`A2UI SSE at http://${displayHost}:${port}${basePath}/api/a2ui/events`);
  log.info(`MCP JSON-RPC at http://${displayHost}:${port}${basePath}/api/mcp`);
  log.info(`A2A Agent Card at http://${displayHost}:${port}${basePath}/.well-known/agent.json`);

  // Start Slack Socket Mode if configured
  const slackConfig = loadConfig().slack;
  if (slackConfig?.appToken) {
    void (async (): Promise<void> => {
      try {
        const { startSlackSocketMode } = await import('../integrations/slack-socket.js');
        const judgeModel = resolveAgentProfileModel('pha');
        const slackLlmCall = async (prompt: string): Promise<string> => {
          const { MockDataSource: SlackMockDS } = await import('../data-sources/mock.js');
          const slackAgent = await createPHAAgent({
            apiKey: judgeModel.apiKey,
            provider: judgeModel.provider as LLMProvider,
            modelId: judgeModel.modelId,
            baseUrl: judgeModel.baseUrl,
            dataSource: new SlackMockDS(),
          });
          return slackAgent.chatAndWait(prompt);
        };
        startSlackSocketMode(slackConfig.appToken!, slackConfig.botToken, slackConfig.channelId, slackLlmCall);
        log.info('Slack Socket Mode started', {
          channelId: slackConfig.channelId ?? 'all channels',
        });
      } catch (err) {
        log.warn('Slack Socket Mode failed to start', { error: String(err) });
      }
    })();
  }

  installProcessHandlers(port);

  return server;
}

